const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const esc=(v='')=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const short=(v='',n=72)=>{const s=String(v||'').replace(/\s+/g,' ').trim();return s.length>n?s.slice(0,n)+'...':s};
const api=async p=>{const r=await fetch(p,{cache:'no-store'});if(!r.ok)throw Error(`${r.status}`);return r.json()};
const state={view:'home',today:{},recent:[],body:[],diet:[],training:[],movements:[],dictionary:[],movementGroups:[],movementSelection:'',movementHistory:null,movementUsage:{},usageLoaded:false,selectedBodyPart:null,page:1,syncStatus:null,archiveHealth:null,dataCheck:null,dataCheckOverlayOpen:false,saving:false,composing:false,trainingQuery:'',trainingOrder:'recent',movementQuery:'',routeParams:{},routeState:null,hoverTimer:null,hoverNode:null,movementMerge:null,buildInfo:null};
const main=$('#main'),root=$('#overlay-root'),toast=$('#toast');
const showToast=t=>{toast.textContent=t;toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2600)};
const dateOf=r=>String(r.Date||r.date||'').slice(0,10), value=(o,...keys)=>keys.map(k=>o?.[k]).find(v=>v!==undefined&&v!==null&&v!=='')??'-';
function buildIdentityLabel(info){const status=String(info?.status||'UNKNOWN').toUpperCase(),shortSha=info?.short_sha||'';if(status==='PUBLISHED')return `FORMAL · ${shortSha} · PUBLISHED`;if(status==='PREVIEW')return `PREVIEW · ${info?.branch||'WORKTREE'} · ${shortSha||'UNKNOWN'}${info?.dirty===true?' · DIRTY':''}`;if(status==='UNVERIFIED')return `FORMAL · ${shortSha||'UNKNOWN'} · UNVERIFIED`;return 'BUILD UNKNOWN'}
function renderBuildIdentity(){const button=$('[data-build-identity]');if(!button)return;const info=state.buildInfo||{};button.dataset.buildStatus=String(info.status||'UNKNOWN').toLowerCase();button.querySelector('.build-identity-label').textContent=buildIdentityLabel(info);button.title=info.dirty===true?'Preview 工作区存在未提交修改':`运行版本：${String(info.status||'UNKNOWN').toUpperCase()}`}
async function loadBuildInfo(){try{state.buildInfo=await api('/api/build-info')}catch{state.buildInfo={status:'UNKNOWN',mode:'unknown'}}renderBuildIdentity()}
function buildIdentityDetails(){const info=state.buildInfo||{},rows=[['运行模式',info.mode||'unknown'],['状态',info.status||'UNKNOWN'],['完整 Commit SHA',info.commit_sha||'不可用'],['来源分支',info.branch||'不可用'],['部署生成时间',info.generated_at||'不可用'],['服务启动时间',info.server_started_at||'不可用'],['部署时 main SHA',info.main_sha||'不可用'],['部署时 origin/main SHA',info.origin_main_sha||'不可用'],['Push 已验证',info.push_verified===true?'是':info.push_verified===false?'否':'不可用'],['Preview 工作区',info.dirty===true?'DIRTY / 有未提交修改':info.dirty===false?'CLEAN / 干净':'不可用'],['Tag',info.tag||'无']];return `<div class="build-identity-details"><div class="build-identity-status"><span class="eyebrow">RUNTIME IDENTITY</span><h3>${esc(buildIdentityLabel(info))}</h3><p>这是当前运行服务的部署身份，不是后台实时远端监控。</p></div><dl>${rows.map(([label,value])=>`<div><dt>${esc(label)}</dt><dd>${esc(value)}</dd></div>`).join('')}</dl>${info.commit_sha?`<button class="btn build-copy-sha" data-build-copy-sha>复制完整 SHA</button>`:''}</div>`}
function openBuildIdentity(){const button=$('[data-build-identity]');if(button)button.setAttribute('aria-expanded','true');modal('运行版本与部署身份',buildIdentityDetails(),{light:true,actions:'<button class="btn btn-primary" data-close>关闭</button>'})}

function statusPanel(){const t=state.today,b=t.body||{},d=t.diet||{},tr=t.training||{};return `<section class="status-panel"><span class="eyebrow">TODAY / STATUS</span><h2>${esc(t.date||'No record')}</h2><div class="status-row"><span>Weight 体重</span><strong>${esc(value(b,'Weight (kg)'))} kg</strong></div><div class="status-row"><span>Bowel 排便</span><strong>${esc(value(b,'Bowel Movement'))}</strong></div><div class="status-row"><span>Calories 热量</span><strong>${esc(value(d,'Calories (kcal)'))} kcal</strong></div><div class="status-row"><span>Training 分部</span><strong>${esc(value(tr,'split','Split'))}</strong></div><div class="status-row"><span>Cardio 有氧</span><strong>${esc(value(t,'cardio'))}</strong></div></section>`}
function renderArchiveHealth(){const nav=$('[data-health-nav-entry]'),marker=nav?.querySelector('.health-nav-status'),toolsStatus=$('[data-tools-health-status]'),health=state.archiveHealth,count=Number(health?.issue_count||0),needsReview=health?.status==='NEEDS_REVIEW'&&count>0,normalLabel='查看待处理的数据问题';if(nav&&marker){nav.hidden=!needsReview;marker.hidden=!needsReview;marker.className=`health-nav-status${needsReview?' needs-review':''}`;if(!needsReview){marker.textContent='';nav.removeAttribute('title');nav.setAttribute('aria-label',normalLabel)}else{marker.textContent=String(count);nav.title=`待处理数据问题：${count} 个`;nav.setAttribute('aria-label',`待处理数据问题：${count} 个`)}}if(toolsStatus){const unavailable=health?.status==='UNAVAILABLE',loading=!health?.status;toolsStatus.dataset.status=needsReview?'review':unavailable?'unavailable':loading?'loading':'ok';toolsStatus.textContent=needsReview?`${count} 项待处理`:unavailable?'检查暂不可用':loading?'正在检查':'当前无需处理'}}
async function loadArchiveHealth(){try{state.archiveHealth=await api('/api/archive-health')}catch{state.archiveHealth={status:'UNAVAILABLE'}}renderArchiveHealth()}
function recentPanel(title='RECENT SAVED'){return `<section class="rail-section"><div class="rail-head"><span class="eyebrow">${title}</span><button data-go="body">View all -></button></div>${state.recent.slice(0,4).map(r=>`<article class="record"><h3>${esc(r.date)}</h3><p>${esc(r.weight||'-')} kg / ${esc(r.bowel||'-')} / ${esc(r.calories||'-')} kcal</p><p>${esc(r.split||'Rest')} / ${esc(r.cardio||'No cardio')}</p><div class="record-actions"><button data-record="${esc(r.date)}">Open detail</button><button data-go="training">Training</button><button data-go="diet">Diet</button></div></article>`).join('')}</section>`}
const pageHeader=(title,sub)=>`<header><h1 class="page-title">${title}</h1><p class="page-subtitle">${sub}</p><span class="accent-line"></span></header>`;
const pager=()=>`<div class="pagination records-status"><span>Showing local records</span></div>`;

function homePage(){const t=state.today,b=t.body||{},d=t.diet||{},tr=t.training||{};main.innerHTML=`<section class="home-page"><div class="home-stage"><div class="home-copy"><span class="home-index">01</span><span class="eyebrow">LOCAL FITNESS JOURNAL</span><h1>Daily<br>Capture</h1><p>记录身体、饮食与训练，把自由文字沉淀为可回看的个人档案。</p><div class="home-actions"><button class="btn btn-primary" data-go="quick">Write today's log <span>→</span></button><button class="home-text-link" data-go="movements">Explore movement archive</button></div></div><div class="home-photo" aria-hidden="true"></div><aside class="home-slip"><span class="eyebrow">LATEST ENTRY / ${esc(t.date||'—')}</span><div class="home-slip-value">${esc(value(b,'Weight (kg)'))}<small>kg</small></div><div class="home-slip-row"><span>${esc(value(tr,'split','Split'))}</span><span>${esc(value(d,'Calories (kcal)'))} kcal</span></div><div class="home-slip-row"><span>${esc(value(t,'cardio'))}</span></div></aside><div class="home-orbit">FREEFORM · REVIEW · STRUCTURED · PRIVATE ·</div></div><section class="home-index-strip"><div class="home-index-head"><span><b>02</b> RECENT ARCHIVE</span><button data-go="body">View full journal →</button></div><div class="home-tickets">${state.recent.slice(0,3).map((r,i)=>`<button class="home-ticket" data-record="${esc(r.date)}"><span class="ticket-no">0${i+1}</span><strong>${esc(r.date)}</strong><small>${esc(r.weight||'—')} kg · ${esc(r.split||'Rest')}</small><em>${esc(r.calories||'—')} kcal</em></button>`).join('')}</div></section></section>`}

function quickPage(){main.innerHTML=`<section class="page entry-page"><header class="entry-header"><div><span class="eyebrow">02 / DAILY ENTRY</span><h1 class="page-title">Write the day.</h1><p class="page-subtitle">Freeform first. Structure follows after review.</p></div><button class="home-text-link" data-go="home">← Back to Home</button></header><div class="entry-spread"><article class="capture"><span class="eyebrow">FREEFORM → STRUCTURED</span><h2>Raw first. Structure second.</h2><textarea id="raw-entry" placeholder="写下今天的任何内容…"></textarea><div class="actions"><button class="btn btn-primary" id="parse">Parse & Review →</button><button class="btn btn-light" data-mock="Undo remains in the stable desktop app.">Undo last save</button></div><p class="phase">Read-only Web preview. Formal writes remain in the stable desktop app.</p></article><aside class="entry-aside">${statusPanel()}${recentPanel()}</aside></div></section>`}

function bodyPage(){main.innerHTML=`<section class="page archive-page"><div class="archive-heading">${pageHeader('Body Records','Daily measurements read as an archive, not a spreadsheet.')}</div><div class="toolbar"><input class="control search" id="body-search" placeholder="Search notes…"><select class="control"><option>All time</option></select><select class="control"><option>Training</option></select><select class="control"><option>Bowel</option></select><select class="control"><option>Cardio</option></select></div><div id="body-rows" class="editorial-records"></div>${pager()}</section>`;renderBodyRows()}
function renderBodyRows(q=''){const rows=state.body.filter(r=>JSON.stringify(r).toLowerCase().includes(q.toLowerCase()));$('#body-rows').innerHTML=rows.map((r,i)=>`<article class="editorial-record ${i===0?'is-featured':''}" data-detail="body" data-index="${state.body.indexOf(r)}"><div class="editorial-date"><span>${String(i+1).padStart(2,'0')}</span><strong>${esc(dateOf(r))}</strong></div><div class="editorial-metrics"><b>${esc(value(r,'Weight (kg)'))}<small>kg</small></b><span>排便 ${esc(value(r,'Bowel Movement'))}</span><span>${esc(value(r,'Training'))}</span><span>${esc(value(r,'Cardio'))}</span></div><p>${esc(short(value(r,'Notes'),110))}</p><button class="record-open">Open record →</button></article>`).join('')}

function dietPage(){main.innerHTML=`<section class="page archive-page diet-archive"><div class="archive-heading">${pageHeader('Diet Records','Meals, macros, and context arranged as daily editorial slips.')}</div><div class="toolbar"><input class="control" value="Recent records" readonly><select class="control"><option>All Meals</option></select><input class="control search" id="diet-search" placeholder="Search notes or food…"></div><div id="diet-rows" class="diet-slips"></div>${pager()}</section>`;renderDietRows()}
function renderDietRows(q=''){const rows=state.diet.filter(r=>JSON.stringify(r).toLowerCase().includes(q.toLowerCase()));$('#diet-rows').innerHTML=rows.map((r,i)=>`<article class="diet-slip ${i%4===1?'slip-offset':''}" data-detail="diet" data-index="${state.diet.indexOf(r)}"><span class="slip-index">${String(i+1).padStart(2,'0')}</span><h3>${esc(dateOf(r))}</h3><div class="macro-line"><strong>${esc(value(r,'Calories (kcal)'))}<small>kcal</small></strong><span>P ${esc(value(r,'Protein (g)'))}</span><span>C ${esc(value(r,'Carbs (g)'))}</span><span>F ${esc(value(r,'Fat (g)'))}</span></div><p>${esc(short(value(r,'Food Summary'),95))}</p><small>${esc(short(value(r,'Notes'),55))}</small><button class="record-open">Read detail →</button></article>`).join('')}

const groupLabel=(group='')=>({Chest:'胸部',Back:'背部',Shoulder:'肩部',Shoulders:'肩部',Legs:'腿部',Arms:'手臂',Biceps:'手臂',Triceps:'手臂',Core:'核心',Cardio:'有氧'}[group]||group||'其他');
function movementPage(){const requestedId=state.routeParams?.movement_id||'';main.innerHTML=`<section class="page movement-index-page"><div class="movement-index-hero"><span class="eyebrow">05 / MOVEMENT ARCHIVE</span><h1>Movement<br>Index</h1><p>按训练部位浏览动作。使用频率更高的动作会自然靠前。</p><button class="movement-dictionary-entry material-control interactive-lift" data-view="dictionary"><span>CONTROLLED VOCABULARY</span><strong>Manage Dictionary</strong><b>→</b></button><div class="movement-toolbar"><input id="movement-search" class="control search" value="${esc(state.movementQuery||'')}" placeholder="Search movement, English name or alias…"><span class="result-count">${state.movements.length} movements</span></div></div><div id="movement-list" class="movement-groups"><div class="loading-page"><i></i><p>Reading movement history…</p></div></div></section>`;if(state.usageLoaded)renderMovementDirectory(state.movementQuery||'');loadMovementUsage();if(requestedId)loadMovementFocus(requestedId)}
async function loadMovementUsage(){if(state.usageLoaded){renderMovementDirectory($('#movement-search')?.value||'');return}const pairs=await Promise.all(state.movements.map(async m=>{const movementId=String(m.movement_id||'');try{const payload=await api(`/api/movement-history?movement_id=${encodeURIComponent(movementId)}&limit=50`);return [movementId,{count:(payload.history||[]).length,payload}]}catch{return [movementId,{count:0,payload:null}]}}));state.movementUsage=Object.fromEntries(pairs);state.usageLoaded=true;renderMovementDirectory($('#movement-search')?.value||'')}
function invalidateMovementUsage(){state.movementUsage={};state.usageLoaded=false;state.movementHistory=null}
function renderMovementDirectory(q=''){const target=$('#movement-list');if(!target)return;const rows=state.movements.filter(m=>JSON.stringify(m).toLowerCase().includes((q||'').toLowerCase())).sort((a,b)=>(state.movementUsage[String(b.movement_id||'')]?.count||0)-(state.movementUsage[String(a.movement_id||'')]?.count||0));const groups=new Map();for(const m of rows){const key=m.muscle_group||'Other';if(!groups.has(key))groups.set(key,[]);groups.get(key).push(m)}const ordered=[...groups.entries()].sort((a,b)=>b[1].reduce((n,m)=>n+(state.movementUsage[String(m.movement_id||'')]?.count||0),0)-a[1].reduce((n,m)=>n+(state.movementUsage[String(m.movement_id||'')]?.count||0),0));const artFor=group=>{const key=String(group||'').toLowerCase();if(/shoulder|肩/.test(key))return'body-themes-v2/shoulders.png';if(/chest|胸/.test(key))return'body-themes-v2/chest.png';if(/back|pull|背/.test(key))return'body-themes-v2/back.png';if(/leg|glute|lower|腿|臀/.test(key))return'body-themes-v2/legs.png';if(/arms?|biceps|triceps|手臂|二头|三头/.test(key))return'body-themes-v2/arms.png';return'movement-art-core.png'};target.innerHTML=ordered.map(([group,items],groupIndex)=>`<section class="movement-group group-${groupIndex%3}"><header><span class="group-number">${String(groupIndex+1).padStart(2,'0')}</span><div><h2>${esc(groupLabel(group))}</h2><p>${esc(group)} · ${items.length} movements</p></div></header><div class="movement-mosaic">${items.map((m,i)=>{const name=m.display_name||m.english_name||m.movement_id,count=state.movementUsage[String(m.movement_id||'')]?.count||0,isLead=i===0&&count;return `<button class="movement-tile ${isLead?'tile-lead':count>=4?'tile-wide':'tile-slip'}" data-select-movement-id="${esc(m.movement_id)}">${isLead?`<img class="movement-art" src="assets/${artFor(group)}" alt="" aria-hidden="true">`:''}<span class="tile-count">${count} sessions</span><strong>${esc(name)}</strong><small>${esc(m.english_name&&m.english_name!==name?m.english_name:groupLabel(group))}</small><em>Open trajectory →</em></button>`}).join('')}</div></section>`).join('')||'<p class="empty-note">No matching movements.</p>';const count=$('.result-count');if(count)count.textContent=`${rows.length} movements`}
async function loadMovementFocus(movementId){state.movementSelection=String(movementId||'');main.innerHTML=`<section class="page movement-detail-page"><button class="movement-back" data-movement-index>← Movement Index</button><div id="movement-focus"><div class="loading-page"><i></i><p>Loading recorded history…</p></div></div></section>`;const focus=$('#movement-focus');try{let payload=state.movementUsage[String(movementId)]?.payload;if(!payload)payload=await api(`/api/movement-history?movement_id=${encodeURIComponent(movementId)}&limit=50`);state.movementHistory=payload;if(!payload.movement){navigate('movements',{}, {replace:true,context:null});return}const movement=payload.movement||{},history=payload.history||[];focus.innerHTML=`<div class="movement-detail-hero"><span class="eyebrow">RECORDED TRAJECTORY</span><h1>${esc(movement.display_name||movementId)}</h1><p>${esc(movement.english_name||movement.muscle_group||'Recorded movement')}</p><div class="movement-meta"><span>${esc(groupLabel(movement.muscle_group))}</span><span>${history.length} recorded sessions</span></div></div><div class="trajectory"><div class="trajectory-line"></div>${history.map((r,i)=>`<article class="trajectory-entry ${i===0?'is-latest':''}"><div class="trajectory-marker">${String(i+1).padStart(2,'0')}</div><div class="history-date"><strong>${esc(r.date||'—')}</strong><small>Day ${esc(r.training_day??'—')} · Ex ${esc(r.order??'—')}</small></div><div class="history-content"><h3>${esc((r.sets_lines||[]).join(' · ')||'Recorded without structured sets')}</h3>${r.notes?`<p>${esc(r.notes)}</p>`:''}</div></article>`).join('')||'<div class="empty-copy"><h3>No history yet</h3><p>This movement exists in the dictionary but has no recorded sessions.</p></div>'}</div>`}catch{focus.innerHTML='<div class="empty-copy"><h3>History unavailable</h3><p>The local read-only service could not load this movement.</p></div>'}}

const issues=[['High','2026-07-01','身体数据','缺少排便记录','补充当天排便信息'],['High','2026-06-29','训练记录','发现未识别动作','审核动作并映射或加入词典'],['Medium','2026-06-30','训练记录','检测到同日重复记录','检查并决定保留或合并'],['Medium','2026-06-25','身体数据','字段内容可能混入其他文字','打开记录并清理字段'],['Medium','2026-06-24','训练记录','动作组数未能结构化识别','核对并补充组数'],['Low','2026-06-20','饮食记录','缺少热量数据','补充当天热量']];
function checksPage(){main.innerHTML=`<section class="page page-grid"><div class="content">${pageHeader('Data Check','Unresolved issues, data hygiene, and structural consistency.')}<div class="toolbar"><button class="btn btn-primary">All Issues &nbsp; 6</button><button class="btn">High 2</button><button class="btn">Medium 3</button><button class="btn">Low 1</button></div><div class="table-wrap"><table><thead><tr><th>SEVERITY</th><th>DATE</th><th>AREA</th><th>ISSUE</th><th>SUGGESTED ACTION</th><th>OPEN</th></tr></thead><tbody>${issues.map((x,i)=>`<tr data-issue="${i}"><td><span class="severity ${x[0].toLowerCase()}">${x[0]}</span></td><td>${x[1]}</td><td>${x[2]}</td><td>${x[3]}</td><td>${x[4]}</td><td><button class="link">Open</button></td></tr>`).join('')}</tbody></table></div>${pager()}</div><aside class="rail"><section class="rail-section" style="margin-top:0"><span class="eyebrow">NEW MOVEMENT APPROVAL</span><h2 style="font:400 24px var(--serif)">Movement detected</h2><p>Z-Press (Dumbbell)</p><button class="btn btn-primary" data-approval style="width:100%">Review decision</button></section><section class="rail-section"><span class="eyebrow">COMPONENT STATES</span><div class="state-stack" style="margin-top:16px"><div class="state">Empty · No matching issues</div><div class="state">Loading · Scanning data</div><div class="state success">Success · All good</div><div class="state warning">Warning · Needs attention</div><div class="state error">Error · Scan interrupted</div></div></section><p style="color:#666;font-size:11px">UI preview only. The stable desktop checker remains authoritative.</p></aside></section>`}

function reviewPage(raw){main.innerHTML=`<section class="page review"><div class="review-top">${pageHeader('Parse & Review','Review extracted data before saving to your local journal.')}<button class="btn" data-back>Back to edit</button></div><div class="summary-strip">${[['Date','2026-07-01'],['Weight','67.8 kg'],['Bowel','少量'],['Calories','1570 kcal'],['Training','胸部, 肩部'],['Movements','6 · New 1']].map(x=>`<div class="metric"><label>${x[0]}</label><strong>${x[1]}</strong></div>`).join('')}</div>${['BODY 身体','DIET 饮食','TRAINING 训练','MOVEMENTS 动作识别','WARNINGS 警告'].map((t,i)=>`<section class="review-section"><h3>${t}</h3><p>${i===4?'Duplicate date · New movement · Unrecognized sets':i===3?'1. 卧推 · 4 sets &nbsp; 2. 引体向上 · 3 sets &nbsp; 3. 绳索面拉 · 3 sets':esc(short(raw||'Preview data from the current draft.',180))}</p></section>`).join('')}<div class="bottom-bar"><button class="btn" data-back>Cancel</button><button class="btn" data-back>← Back to edit</button><button class="btn btn-primary" data-duplicate>Confirm & Save</button></div></section>`}

function modal(title,content,{light=false,actions=''}={}){root.innerHTML=`<div class="overlay"><section class="modal ${light?'light':''}"><button class="close" data-close>×</button><h2>${esc(title)}</h2>${content}${actions?`<div class="modal-actions">${actions}</div>`:''}</section></div>`}
function detail(kind,index){const map={body:state.body,diet:state.diet,training:state.training},r=map[kind][index];const rows=Object.entries(r||{}).filter(([,v])=>v!==''&&v!=null).map(([k,v])=>`<div class="detail-row"><label>${esc(k)}</label><div>${esc(typeof v==='object'?JSON.stringify(v):v)}</div></div>`).join('');modal(`${kind[0].toUpperCase()+kind.slice(1)} Detail`,rows,{light:kind==='diet',actions:`<button class="btn" data-mock="Editing is available in the stable desktop app.">Edit</button><button class="btn btn-primary" data-close>Close</button>`})}
const readable=(object,...keys)=>keys.map(key=>object?.[key]).find(item=>item!==undefined&&item!==null&&item!=='')??'—';
function detailFacts(items){return `<div class="structured-facts">${items.map(([label,val,unit=''])=>`<div><span>${esc(label)}</span><strong>${esc(val)}${val!=='—'&&unit?` <small>${esc(unit)}</small>`:''}</strong></div>`).join('')}</div>`}
function rawDisclosure(label,raw){if(!raw||raw==='—')return'';const text=typeof raw==='string'?raw:(raw.raw_text||raw.text||raw.raw||'');return text?`<details class="raw-disclosure"><summary>${esc(label)}</summary><pre>${esc(text)}</pre></details>`:''}
function setsHtml(movement){const sets=movement.sets||movement.structured_sets||[];if(Array.isArray(sets)&&sets.length)return `<div class="structured-sets">${sets.map((set,index)=>`<div><span>${index+1}</span><b>${esc(readable(set,'weight_text','weight','load','load_text'))}</b><em>${esc(readable(set,'reps'))} 次</em><em>${esc(readable(set,'sets','set_count'))} 组</em></div>`).join('')}</div>`;const summary=readable(movement,'sets_summary','sets_text','raw_detail','detail');return summary!=='—'?`<p class="structured-summary">${esc(summary)}</p>`:'<p class="structured-empty">暂无结构化组数</p>'}
function trainingHtml(sessions=[]){return sessions.map((session,sessionIndex)=>{const movements=session.movements||session.exercises||[];return `<article class="structured-session"><header><div><span>训练 ${sessionIndex+1}</span><h3>${esc(readable(session,'split','Split','training'))}</h3></div><small>${esc(readable(session,'day_number','training_day','date','Date'))}</small></header>${movements.length?`<div class="structured-movements">${movements.map((movement,index)=>`<section><div class="structured-movement-head"><span>${String(index+1).padStart(2,'0')}</span><h4>${esc(readable(movement,'display_name','movement_name','name','movement'))}</h4>${movement.standardized===false?'<small>未标准化</small>':''}</div>${setsHtml(movement)}${readable(movement,'notes','note')!=='—'?`<p class="structured-note">${esc(readable(movement,'notes','note'))}</p>`:''}${rawDisclosure('查看动作原始写法',readable(movement,'raw','raw_detail'))}</section>`).join('')}</div>`:`<p class="structured-summary">${esc(readable(session,'Standardized Summary','standardized_summary','movement_summary'))}</p>`}${readable(session,'notes','Notes')!=='—'?`<p class="structured-note"><b>训练备注</b>${esc(readable(session,'notes','Notes'))}</p>`:''}${rawDisclosure('查看训练原始记录',readable(session,'raw_record','Raw Record','raw'))}</article>`}).join('')||'<p class="structured-empty">当日没有训练记录</p>'}
function structuredRecordHtml(record){const body=record.body||{},diet=record.diet||{},sessions=Array.isArray(record.training)?record.training:record.training?[record.training]:[],rawEntries=record.raw_entries||[];return `<div class="structured-record"><section class="structured-section is-summary"><span class="eyebrow">记录摘要</span>${detailFacts([['日期',record.date||'—'],['训练主题',readable(sessions[0],'split','Split','training')],['体重',readable(body,'Weight (kg)','weight'),'kg'],['排便',readable(body,'Bowel Movement','bowel')],['有氧',readable(body,'Cardio','cardio')],['热量',readable(diet,'Calories (kcal)','calories'),'kcal']])}</section><section class="structured-section"><h3>身体记录</h3>${detailFacts([['体重',readable(body,'Weight (kg)','weight'),'kg'],['排便',readable(body,'Bowel Movement','bowel')],['有氧',readable(body,'Cardio','cardio')]])}${readable(body,'Notes','notes')!=='—'?`<p class="structured-note">${esc(readable(body,'Notes','notes'))}</p>`:''}</section><section class="structured-section"><h3>饮食记录</h3>${detailFacts([['热量',readable(diet,'Calories (kcal)','calories'),'kcal'],['蛋白质',readable(diet,'Protein (g)','protein'),'g'],['碳水',readable(diet,'Carbs (g)','carbs'),'g'],['脂肪',readable(diet,'Fat (g)','fat'),'g']])}${readable(diet,'Food Summary','food_summary')!=='—'?`<div class="structured-copy"><b>饮食摘要</b><p>${esc(readable(diet,'Food Summary','food_summary'))}</p></div>`:''}${readable(diet,'Notes','notes')!=='—'?`<p class="structured-note">${esc(readable(diet,'Notes','notes'))}</p>`:''}</section><section class="structured-section"><h3>训练记录</h3>${trainingHtml(sessions)}</section>${rawEntries.map((entry,index)=>rawDisclosure(`查看原始输入 ${index+1}`,entry)).join('')}</div>`}
async function recordDetail(date){modal(date,'<div class="loading-page" style="height:240px"><i></i></div>');try{const record=await api(`/api/record?date=${encodeURIComponent(date)}`),panel=$('.modal');panel.classList.add('structured-detail-modal');panel.innerHTML=`<button class="close" data-close>×</button><span class="eyebrow">DAILY RECORD / STRUCTURED</span><h2>${esc(date)}</h2>${structuredRecordHtml(record)}`}catch{showToast('无法读取该日记录详情。')}}
async function movementDetail(movementId){modal(movementId,'<div class="loading-page" style="height:240px"><i></i></div>');try{const h=await api(`/api/movement-history?movement_id=${encodeURIComponent(movementId)}&limit=8`);$('.modal').innerHTML=`<button class="close" data-close>×</button><span class="eyebrow">MOVEMENT HISTORY</span><h2>${esc(h.movement?.display_name||movementId)}</h2><div class="detail-list">${(h.history||h.records||h||[]).map(r=>`<div class="detail-row"><label>${esc(dateOf(r))}</label><div>${esc(short(value(r,'sets_summary','raw_detail','detail'),220))}</div></div>`).join('')||'<p>No structured history found.</p>'}<div class="modal-actions"><button class="btn" data-drawer="movement">Open editor preview</button><button class="btn btn-primary" data-close>Close</button></div>`}catch{showToast('Unable to load movement history.')}}
function drawer(type){const light=type==='movement';root.innerHTML=`<div class="overlay" data-close></div><aside class="drawer ${light?'light':''}"><button class="close" data-close>×</button><span class="eyebrow" style="${light?'color:#676962':''}">${type==='movement'?'MOVEMENT EDITOR':'RECORD EDITOR · UI PREVIEW'}</span><h2 style="font:400 30px var(--serif)">${type==='movement'?'Movement record':'Edit Body Record'}</h2>${['Date','Name / Training','Weight or Sets','Cardio','Notes'].map((f,i)=>`<label class="field"><span>${f}</span>${i===4?'<textarea rows="5">Preview only</textarea>':`<input value="${i===0?'2026-07-01':''}">`}</label>`).join('')}<button class="btn btn-primary" style="width:100%" data-mock="Write actions are intentionally disabled in Web preview.">Save changes</button></aside>`}
function duplicate(){modal('Duplicate Date Detected',`<p>2026-07-01 的记录已存在。请选择如何处理此记录：</p><div class="detail-list"><button class="btn btn-primary" data-mock="Overwrite is disabled in read-only preview.">Overwrite daily records →</button><button class="btn btn-light" data-mock="Adding a session is disabled in read-only preview.">Add as second training session →</button><button class="btn btn-light" data-close>Cancel</button></div>`,{light:true})}
function approval(){modal('New movement approval',`<p>This movement is not in your dictionary.</p><div class="detail-row"><label>Detected</label><strong>Z-Press (Dumbbell)</strong></div><div class="detail-list"><label class="record"><input type="radio" name="a" checked> Add to dictionary</label><label class="record"><input type="radio" name="a"> Map to existing movement</label><label class="record"><input type="radio" name="a"> Keep raw only</label></div>`,{actions:`<button class="btn" data-close>Cancel</button><button class="btn btn-primary" data-mock="Approval is a UI preview only.">Save decision</button>`})}

