function compactEntryAside(){const t=state.today,b=t.body||{},d=t.diet||{},tr=t.training||{};return `<aside class="entry-compact-aside"><section class="entry-today-compact material-frosted edge-highlight"><span class="receipt-pin" aria-hidden="true"></span><span class="eyebrow">LATEST ENTRY / ${esc(t.date||'NO RECORD')}</span><div class="today-weight"><strong>${esc(value(b,'Weight (kg)'))}</strong><small>kg</small></div><div class="today-facts"><span><b>${esc(value(d,'Calories (kcal)'))}</b> kcal</span><span><b>${esc(value(tr,'split','Split'))}</b> training</span><span><b>${esc(value(t,'cardio'))}</b> cardio</span><span><b>${esc(value(b,'Bowel Movement'))}</b> bowel</span></div></section><section class="entry-recent-compact archive-slip"><div class="rail-head"><span class="eyebrow">RECENT SAVED</span><button data-go="body">View all →</button></div>${state.recent.slice(0,2).map((r,i)=>`<div class="compact-record archive-card interactive-lift" style="--slip-index:${i}"><span>0${i+1}</span><div><strong>${esc(r.date)}</strong><small>${esc(r.weight||'—')} kg · ${esc(r.calories||'—')} kcal<br>${esc(r.split||'Rest')}</small></div><button data-record="${esc(r.date)}">Open</button></div>`).join('')}</section></aside>`}
