bodyPage=function(){main.innerHTML=`<section class="page archive-page body-archive"><div class="body-folio">BODY / LOCAL ARCHIVE / PRIVATE</div><div class="archive-heading">${pageHeader('Body Records','Daily measurements as personal body slips, with notes kept readable.')}</div><div class="toolbar body-toolbar"><input class="control search" id="body-search" placeholder="Search notes or date..."><select class="control" id="body-time"><option value="0">All time</option><option value="7">Recent 7 days</option><option value="14">Recent 14 days</option><option value="30">Recent 30 days</option></select><select class="control" id="body-order"><option value="recent">Newest first</option><option value="oldest">Oldest first</option></select></div><div id="body-rows" class="body-ledger"></div>${pager()}</section>`;renderBodyRows()}
renderBodyRows=function(q=$('#body-search')?.value||''){const days=Number(selectedValue('body-time')||0);let rows=state.body.filter(r=>fuzzyMatch(r,q)).filter(r=>withinDays(r,days,state.body));if(selectedValue('body-order')==='oldest')rows=[...rows].reverse();$('#body-rows').innerHTML=rows.map((r,i)=>{const cardio=String(value(r,'Cardio')).toLowerCase(),training=String(value(r,'Training'));let tone='tone-purple';if(i===0)tone='tone-feature';else if(/back|背/.test(training.toLowerCase()))tone='tone-cardio';else if(/chest|胸|shoulder|肩/.test(training.toLowerCase()))tone='tone-purple';else if(/leg|腿/.test(training.toLowerCase()))tone='tone-training';else if(/none|no cardio|-/.test(cardio))tone='tone-rest';return `<article class="body-slip ${tone}"><div class="body-slip-date"><span>${String(i+1).padStart(2,'0')}</span><strong>${esc(dateOf(r))}</strong></div><div class="body-slip-weight"><b>${esc(value(r,'Weight (kg)'))}</b><small>kg</small></div><div class="body-slip-meta"><span>Bowel <strong>${esc(value(r,'Bowel Movement'))}</strong></span><span>Training <strong>${esc(short(training,24))}</strong></span><span>Cardio <strong>${esc(short(value(r,'Cardio'),24))}</strong></span></div><div class="body-slip-copy"><p>${esc(short(value(r,'Notes'),160))}</p><button class="record-open" data-detail="body" data-index="${state.body.indexOf(r)}">Open record</button></div></article>`}).join('')||'<p class="empty-note">No body records match this search.</p>'}

dietPage=function(){main.innerHTML=`<section class="page archive-page diet-archive"><div class="archive-heading">${pageHeader('Diet Records','Energy and macros first. Full meals remain one deliberate click away.')}</div><div class="toolbar diet-toolbar"><input class="control search" id="diet-search" placeholder="Search notes, food or date..."><select class="control" id="diet-order"><option value="recent">Newest first</option><option value="oldest">Oldest first</option></select></div><div id="diet-rows" class="diet-slips"></div>${pager()}</section>`;renderDietRows()}
renderDietRows=function(q=$('#diet-search')?.value||''){let rows=state.diet.filter(r=>fuzzyMatch(r,q));if(selectedValue('diet-order')==='oldest')rows=[...rows].reverse();$('#diet-rows').innerHTML=rows.map((r,i)=>`<article class="diet-slip ${i%4===1?'slip-offset':''}"><span class="slip-index">${String(i+1).padStart(2,'0')}</span><h3>${esc(dateOf(r))}</h3><div class="macro-line"><strong>${esc(value(r,'Calories (kcal)'))}<small>kcal</small></strong><span>P ${esc(value(r,'Protein (g)'))}</span><span>C ${esc(value(r,'Carbs (g)'))}</span><span>F ${esc(value(r,'Fat (g)'))}</span></div><div class="diet-summary"><span>MEAL INDEX</span><p>${esc(short(value(r,'Food Summary'),68))}</p></div><button class="record-open" data-detail="diet" data-index="${state.diet.indexOf(r)}">Read detail</button></article>`).join('')||'<p class="empty-note">No diet records match this search.</p>'}

function movementArtFor(group){const key=String(group||'').toLowerCase();if(/shoulder|肩/.test(key))return'body-themes-v2/shoulders.png';if(/arms?|biceps|triceps|手臂|二头|三头/.test(key))return'body-themes-v2/arms.png';if(/back|pull|背/.test(key))return'body-themes-v2/back.png';if(/chest|胸/.test(key))return'body-themes-v2/chest.png';if(/leg|glute|lower|腿|臀/.test(key))return'body-themes-v2/legs.png';return'movement-art-core.png'}
function movementGroupClass(group){const key=String(group||'').toLowerCase();if(/leg|glute|lower|腿|臀/.test(key))return'group-legs';if(/shoulder|肩/.test(key))return'group-shoulders';if(/back|pull|背/.test(key))return'group-back';if(/chest|胸/.test(key))return'group-chest';if(/arms?|biceps|triceps|手臂|二头|三头/.test(key))return'group-arms';return'group-core'}
function layoutMovementMasonry(){const grid=$('.movement-groups');if(!grid)return;const groups=[...grid.children].filter(node=>node.classList.contains('movement-group'));groups.forEach(group=>group.style.gridRowEnd='auto');if(matchMedia('(max-width:1120px)').matches)return;const style=getComputedStyle(grid),rowHeight=parseFloat(style.gridAutoRows)||4,gap=parseFloat(style.rowGap)||14;groups.forEach(group=>{group.style.gridRowEnd=`span ${Math.max(1,Math.ceil((group.getBoundingClientRect().height+gap)/(rowHeight+gap)))}`})}
renderMovementDirectory=function(q=''){
  clearMovementIndexPreviousPreview();
  const target=$('#movement-list');if(!target)return;
  const usage=m=>state.movementUsage[String(m.movement_id||'')]?.count||0;
  const focus=m=>Number(m.focus_rank||0)>0||Boolean(m.pinned),rank=m=>Number(m.focus_rank||0)>0?Number(m.focus_rank):Number.MAX_SAFE_INTEGER;
  const rows=state.movements.filter(m=>fuzzyMatch(m,q)).sort((a,b)=>Number(focus(b))-Number(focus(a))||rank(a)-rank(b)||usage(b)-usage(a)||String(a.display_name||'').localeCompare(String(b.display_name||''),'zh-CN'));
  const groups=new Map();for(const m of rows){const key=m.muscle_group||'Other';if(!groups.has(key))groups.set(key,[]);groups.get(key).push(m)}
  const ordered=[...groups.entries()].sort((a,b)=>b[1].reduce((n,m)=>n+usage(m),0)-a[1].reduce((n,m)=>n+usage(m),0));
  target.innerHTML=ordered.map(([group,items],groupIndex)=>{
    const header=`<img class="movement-group-art" src="assets/${movementArtFor(group)}" alt="" aria-hidden="true"><header><span class="group-number">${String(groupIndex+1).padStart(2,'0')}</span><div><h2>${esc(groupLabel(group))}</h2><p>${esc(group)} · ${items.length} movements</p></div></header>`;
    return `<section class="movement-group group-${groupIndex%3} ${movementGroupClass(group)}">${header}<div class="movement-mosaic">${items.map((m,i)=>{const movementId=String(m.movement_id||''),name=m.display_name||m.english_name||movementId,count=usage(m),hasPreview=Boolean(state.movementUsage[movementId]?.payload?.history?.[0]);return `<button class="movement-tile ${i===0&&count?'tile-lead':count>=4?'tile-wide':'tile-slip'} ${hasPreview?'has-index-previous-record':''}" data-select-movement-id="${esc(movementId)}" data-index-preview-movement-id="${esc(movementId)}">${m.pinned?'<span class="movement-focus-mark">★ FOCUS</span>':''}<span class="tile-count">${count} sessions</span>${hasPreview?'<span class="movement-index-preview-cue">HOLD · LAST SESSION</span>':''}<strong>${esc(name)}</strong><small>${esc(m.english_name&&m.english_name!==name?m.english_name:groupLabel(group))}</small><em>Open trajectory →</em></button>`}).join('')}</div></section>`
  }).join('')||'<p class="empty-note">No matching movements.</p>';
  const count=$('.result-count');if(count)count.textContent=`${rows.length} movements`;
  requestAnimationFrame(()=>requestAnimationFrame(layoutMovementMasonry));
}
loadMovementFocus=async function(movementId){state.movementSelection=String(movementId||'');main.innerHTML=`<section class="page movement-detail-page"><button class="movement-back" data-movement-index>← Movement Index</button><div id="movement-focus"><div class="loading-page"><i></i><p>Loading recorded history…</p></div></div></section>`;const focus=$('#movement-focus');try{let payload=state.movementUsage[String(movementId)]?.payload;if(!payload)payload=await api(`/api/movement-history?movement_id=${encodeURIComponent(movementId)}&limit=50`);state.movementHistory=payload;if(!payload.movement){navigate('movements',{}, {replace:true,context:null});return}const movement=payload.movement||{},history=payload.history||[],latest=history[0],earliest=history[history.length-1],art=movementArtFor(movement.muscle_group);focus.innerHTML=`<div class="movement-detail-compact"><img src="assets/${art}" alt="" aria-hidden="true"><div><span class="eyebrow">RECORDED TRAJECTORY</span><h1>${esc(movement.display_name||movementId)}</h1><p>${esc(movement.english_name||movement.muscle_group||'Recorded movement')}</p></div><div class="movement-detail-stats"><span><b>${history.length}</b> sessions</span><span><b>${esc(latest?.date||'—')}</b> latest</span><span><b>${esc(earliest?.date||'—')}</b> first</span></div></div><div class="trajectory-heading"><span class="eyebrow">PROGRESSION / NEWEST FIRST</span><h2>Training trajectory</h2><p>每次训练的负重、次数、组数和备注按时间展开。</p></div><div class="trajectory"><div class="trajectory-line"></div>${history.map((r,i)=>`<article class="trajectory-entry ${i===0?'is-latest':''}"><div class="trajectory-marker">${String(i+1).padStart(2,'0')}</div><button class="history-date history-date-link" data-training-date="${esc(r.date||'')}" data-training-movement-id="${esc(movement.movement_id||movementId)}"><strong>${esc(r.date||'?')}</strong><small>Day ${esc(r.training_day??'?')} ? Ex ${esc(r.order??'?')}</small></button><div class="history-content"><h3>${esc((r.sets_lines||[]).join(' · ')||'Recorded without structured sets')}</h3>${r.notes?`<p>${esc(r.notes)}</p>`:''}</div></article>`).join('')||'<div class="empty-copy"><h3>No history yet</h3><p>This movement exists in the dictionary but has no recorded sessions.</p></div>'}</div>`}catch{focus.innerHTML='<div class="empty-copy"><h3>History unavailable</h3><p>The local read-only service could not load this movement.</p></div>'}}

function movementRecordMetrics(record){let maxLoad=0,volume=0,totalReps=0,comparable=false;for(const line of record.sets_lines||[]){const pattern=/(\d+(?:\.\d+)?)\s*(?:kg)?\s*[×x*]\s*(\d+)\s*[×x*]\s*(\d+)/gi;let match;while((match=pattern.exec(line))){const load=Number(match[1]),reps=Number(match[2]),sets=Number(match[3]);if(reps<=0||sets<=0)continue;comparable=true;maxLoad=Math.max(maxLoad,load);volume+=load*reps*sets;totalReps+=reps*sets}if(/自重|body\s*weight|\bbw\b/i.test(line)){const body=line.match(/[×x*]\s*(\d+)\s*[×x*]\s*(\d+)/i);if(body){const reps=Number(body[1]),sets=Number(body[2]);if(reps>0&&sets>0){comparable=true;totalReps+=reps*sets;volume+=reps*sets}}}}return {maxLoad,volume,totalReps,comparable}}
function movementProgressChart(history){const available=history.slice(0,8).reverse().map(record=>({...record,...movementRecordMetrics(record)})).filter(record=>record.comparable);if(!available.length)return `<section class="movement-progress-panel is-empty"><div class="progress-copy"><span class="eyebrow">RECENT 8 / VISUAL SUMMARY</span><h2>Recent change</h2></div><p class="progress-empty-copy">No comparable structured data yet</p></section>`;const latestRecord=available.at(-1),useLoad=latestRecord.maxLoad>0,records=available.filter(record=>useLoad?record.maxLoad>0:record.maxLoad===0),values=records.map(record=>useLoad?record.maxLoad:record.totalReps),volumes=records.map(record=>record.volume),maxValue=Math.max(...values,1),maxVolume=Math.max(...volumes,1),left=48,right=682,width=right-left,step=records.length>1?width/(records.length-1):0;const points=records.map((record,index)=>`${left+index*step},${145-(values[index]/maxValue)*92}`).join(' '),bars=records.map((record,index)=>{const height=(volumes[index]/maxVolume)*70,x=left+index*step-12;return `<rect x="${x}" y="${160-height}" width="24" height="${height}" rx="4"></rect>`}).join(''),dots=records.map((record,index)=>`<circle cx="${left+index*step}" cy="${145-(values[index]/maxValue)*92}" r="5"></circle>`).join(''),labels=records.map((record,index)=>`<text x="${left+index*step}" y="194" text-anchor="middle">${esc(String(record.date||'').slice(5))}</text>`).join(''),latest=values.at(-1),previous=values.length>1?values.at(-2):null,delta=previous===null?null:Math.round((latest-previous)*10)/10;return `<section class="movement-progress-panel"><div class="progress-copy"><span class="eyebrow">RECENT 8 / VISUAL SUMMARY</span><h2>Recent change</h2><p>${useLoad?'折线为最高负重，柱形为估算训练容量。':'自重动作以总次数趋势显示，柱形同步表达训练工作量。'}</p></div><div class="progress-signal"><span>Latest</span><strong>${latest}${useLoad?' kg':' reps'}</strong>${delta===null?'':`<small class="${delta>0?'up':delta<0?'down':''}">${delta>0?'+':''}${delta} vs previous</small>`}</div><svg class="progress-chart" viewBox="0 0 730 220" role="img" aria-label="Recent movement progression"><g class="chart-grid"><line x1="48" y1="53" x2="682" y2="53"></line><line x1="48" y1="99" x2="682" y2="99"></line><line x1="48" y1="145" x2="682" y2="145"></line></g><g class="volume-bars">${bars}</g><polyline class="load-line" points="${points}"></polyline><g class="load-dots">${dots}</g><g class="chart-labels">${labels}</g></svg></section>`}
loadMovementFocus=async function(movementId){state.movementSelection=String(movementId||'');main.innerHTML=`<section class="page movement-detail-page"><button class="movement-back" data-movement-index>← Movement Index</button><div id="movement-focus"><div class="loading-page"><i></i><p>Loading recorded history…</p></div></div></section>`;const focus=$('#movement-focus');try{let payload=state.movementUsage[String(movementId)]?.payload;if(!payload)payload=await api(`/api/movement-history?movement_id=${encodeURIComponent(movementId)}&limit=50`);state.movementHistory=payload;if(!payload.movement){navigate('movements',{}, {replace:true});return}const movement=payload.movement||{},history=payload.history||[],latest=history[0],earliest=history[history.length-1],art=movementArtFor(movement.muscle_group),groupClass=movementGroupClass(movement.muscle_group),display=movement.display_name||movementId,longClass=String(display).length>5?'is-long':'';focus.innerHTML=`<div class="movement-detail-compact ${groupClass} ${longClass}"><img class="movement-detail-art" src="assets/${art}" alt="" aria-hidden="true"><div class="movement-detail-title"><span class="eyebrow">RECORDED TRAJECTORY</span><h1>${esc(display)}</h1><p>${esc(movement.english_name||movement.muscle_group||'Recorded movement')}</p></div><div class="movement-detail-stats"><span><b>${history.length}</b> sessions</span><span><b>${esc(latest?.date||'—')}</b> latest</span><span><b>${esc(earliest?.date||'—')}</b> first</span></div></div>${movementProgressChart(history)}<div class="trajectory-heading"><span class="eyebrow">PROGRESSION / NEWEST FIRST</span><h2>Training trajectory</h2><p>每次训练的日期、有效组数和备注按时间展开。</p></div><div class="trajectory">${history.map((r,i)=>{const sets=(r.sets_lines||[]).filter(Boolean);return `<article class="trajectory-entry ${i===0?'is-latest':''}"><button class="history-date history-date-link" data-training-date="${esc(r.date||'')}" data-training-movement-id="${esc(movement.movement_id||movementId)}"><strong>${esc(r.date||'?')}</strong></button><div class="history-content">${sets.length?`<h3>${esc(sets.join(' · '))}</h3>`:''}${r.notes?`<p>${esc(r.notes)}</p>`:''}</div></article>`}).join('')||'<div class="empty-copy"><h3>No history yet</h3><p>This movement exists in the dictionary but has no recorded sessions.</p></div>'}</div>`}catch{focus.innerHTML='<div class="empty-copy"><h3>History unavailable</h3><p>The local read-only service could not load this movement.</p></div>'}}

async function postApi(path,payload){const response=await fetch(path,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const data=await response.json().catch(()=>({error:'Invalid local service response.'}));if(!response.ok){const error=Error(data.error||`Request failed (${response.status})`);error.status=response.status;error.payload=data;throw error}return data}
const recordEditFields={body:['Date','Weight (kg)','Bowel Movement','Training','Cardio','Notes'],diet:['Date','Calories (kcal)','Protein (g)','Carbs (g)','Fat (g)','Food Summary','Notes'],training:['Date','Split','Raw Record','Standardized Summary','Notes']};
const longRecordFields=new Set(['Food Summary','Raw Record','Standardized Summary','Notes']);
function realRecordDetail(kind,index){const rows={body:state.body,diet:state.diet,training:state.training},record=rows[kind]?.[index];if(!record)return;const fields=recordEditFields[kind]||[];const content=`<form id="record-edit-form" class="record-edit-form" data-record-type="${kind}" data-record-id="${esc(record.id||'')}">${fields.map(field=>`<label class="${longRecordFields.has(field)?'is-wide':''}"><span>${esc(field)}</span>${longRecordFields.has(field)?`<textarea name="${esc(field)}" rows="${field==='Notes'?3:5}">${esc(record[field]??'')}</textarea>`:`<input name="${esc(field)}" value="${esc(record[field]??'')}" ${field==='Date'?'type="date"':''}>`}</label>`).join('')}<p class="record-edit-note">保存前自动创建成对备份。未显示字段和每日原始输入保持不变。</p></form>`;modal(`${kind[0].toUpperCase()+kind.slice(1)} Record`,content,{light:kind==='diet',actions:`<button class="btn" data-close>取消</button><button class="btn btn-primary" data-record-save>保存修改</button>`})}
detail=realRecordDetail;
async function saveRecordEdit(){const form=$('#record-edit-form');if(!form)return;const values=Object.fromEntries(new FormData(form).entries()),button=$('[data-record-save]');button.disabled=true;try{const result=await postApi('/api/record/update',{record_type:form.dataset.recordType,record_id:form.dataset.recordId,values});root.innerHTML='';if(form.dataset.recordType==='training'&&result.status!=='NO_CHANGES')invalidateMovementUsage();await refreshWebState();navigate(form.dataset.recordType);showSaveReceipt(result)}catch(error){button.disabled=false;showSaveReceipt(null,error.message||'记录保存失败。')}}
function movementHistoryEditor(index){const movement=state.movementHistory?.movement,record=state.movementHistory?.history?.[index];if(!movement||!record)return;const cardio=record.cardio||{};modal(`编辑动作记录 · ${movement.display_name}`,`<form id="movement-history-form" class="record-edit-form" data-movement-id="${esc(movement.movement_id)}" data-history-id="${esc(record.id||'')}"><label><span>日期（只读）</span><input value="${esc(record.date||'')}" disabled></label><label><span>动作顺序</span><input name="order" value="${esc(record.order??'')}"></label><label class="is-wide"><span>组数（每行：重量 × 次数 × 组数）</span><textarea name="sets_text" rows="5">${esc((record.sets_lines||[]).join('\n'))}</textarea></label><label><span>有氧分钟</span><input name="duration_minutes" value="${esc(cardio.duration_minutes??'')}"></label><label><span>坡度</span><input name="incline" value="${esc(cardio.incline??'')}"></label><label><span>速度</span><input name="speed" value="${esc(cardio.speed??'')}"></label><label><span>心率</span><input name="heart_rate" value="${esc(cardio.heart_rate??'')}"></label><label class="is-wide"><span>动作备注</span><textarea name="notes" rows="3">${esc(record.notes||'')}</textarea></label><label class="is-wide"><span>原始动作细节</span><textarea name="raw" rows="3">${esc(record.raw||'')}</textarea></label></form>`,{light:true,actions:`<button class="btn" data-close>取消</button><button class="btn btn-primary" data-movement-history-save>保存动作记录</button>`})}
async function saveMovementHistory(){const form=$('#movement-history-form');if(!form)return;const values=Object.fromEntries(new FormData(form).entries()),button=$('[data-movement-history-save]');button.disabled=true;try{const result=await postApi('/api/movement-history/update',{movement_id:form.dataset.movementId,history_id:form.dataset.historyId,values});root.innerHTML='';if(result.status!=='NO_CHANGES')invalidateMovementUsage();await refreshWebState();await loadMovementFocus(state.movementSelection);showSaveReceipt(result)}catch(error){button.disabled=false;showSaveReceipt(null,error.message||'动作记录保存失败。')}}
const baseMovementFocus=loadMovementFocus;
loadMovementFocus=async function(name){clearMovementIndexPreviousPreview();await baseMovementFocus(name);$$('.trajectory-entry').forEach((entry,index)=>{const button=document.createElement('button');button.className='trajectory-edit';button.dataset.movementHistoryEdit=String(index);button.textContent='Edit record';entry.appendChild(button)})};
const reviewValue=(path,fallback='')=>path.split('.').reduce((value,key)=>value?.[key],state.reviewPayload?.review)??fallback;
function setReviewValue(path,value){const parts=path.split('.');let target=state.reviewPayload.review;parts.slice(0,-1).forEach(key=>{target=target[key]??={}});target[parts.at(-1)]=value}
function reviewMetric(label,value,unit=''){return `<div class="review-metric"><span>${label}</span><strong>${esc(value??'缺失')}</strong>${unit?`<small>${unit}</small>`:''}</div>`}
function reviewInput(label,path,{type='text',wide=false,rows=1}={}){const value=reviewValue(path,'');return `<label class="review-field ${wide?'is-wide':''}"><span>${label}</span>${rows>1?`<textarea rows="${rows}" data-review-field="${path}">${esc(value)}</textarea>`:`<input type="${type}" value="${esc(value)}" data-review-field="${path}">`}</label>`}
function reviewSetText(item){if(typeof item!=='object'||item===null)return String(item||'');const load=item.weight_text||item.load||item.weight_label||(Number(item.weight)>0?`${item.weight}kg`:'自重');return `${load} × ${item.reps??'-'} × ${item.sets??1}`}
function movementGroupOptions(selected=''){return state.movementGroups.map(value=>`<option value="${esc(value)}" ${selected===value?'selected':''}>${esc(groupLabel(value))}</option>`).join('')}
function movementReviewRow(movement,index,options){const known=movement.movement_id,action=movement._review_action||(known?'use':'add'),inactive=known&&movement._matched_active===false;return `<article class="review-movement" data-movement-row="${index}"><span class="review-order">${String(movement.order??index+1).padStart(2,'0')}</span><div class="review-movement-copy"><input class="movement-name-input" value="${esc(movement.display_name||movement.name)}" data-movement-name="${index}" aria-label="动作名称"><small>${esc(movement.name)} · ${(movement.sets||[]).length} 组</small><p>${esc((movement.sets||[]).map(reviewSetText).join(' · ')||'未识别到结构化组数')}</p></div><label class="review-note"><span>动作备注</span><input value="${esc(movement.notes||'')}" data-movement-note="${index}"></label><div class="review-decision"><span class="review-status ${known?'is-existing':'is-new'}">${inactive?'已停用 · 仍会记录':known?'已有动作':'新动作'}</span><select data-movement-action="${index}"><option value="use" ${action==='use'?'selected':''}>采用当前识别</option><option value="add" ${action==='add'?'selected':''}>作为独立动作加入</option><option value="map" ${action==='map'?'selected':''}>确为同一动作时合并</option><option value="skip" ${action==='skip'?'selected':''}>仅保留原始记录</option></select><select data-movement-group="${index}" ${action==='add'?'':'disabled'}><option value="">选择已有训练部位…</option>${movementGroupOptions(movement._muscle_group||'')}</select><select data-movement-map="${index}" ${action==='map'?'':'disabled'}><option value="">选择同一个已有动作…</option>${options.map(option=>`<option value="${esc(option.movement_id)}" ${movement._mapped_movement_id===option.movement_id?'selected':''}>${esc(option.display_name)}${option.english_name?` / ${esc(option.english_name)}`:''}</option>`).join('')}</select></div></article>`}
reviewPage=function(payload){state.reviewPayload=payload;state.view='review';$$('.nav-item').forEach(button=>button.classList.toggle('is-active',button.dataset.view==='quick'));const review=payload.review,summary=payload.summary||{},warnings=payload.warnings||[],duplicates=payload.duplicates||{},duplicateCount=Object.values(duplicates).reduce((sum,value)=>sum+Number(value||0),0);main.innerHTML=`<section class="review-scroll-page"><aside class="review-index"><span class="eyebrow">REVIEW INDEX</span>${[['01','Summary'],['02','Body'],['03','Diet'],['04','Training'],['05','Movements'],['06','Warnings']].map(item=>`<a href="#review-${item[1].toLowerCase()}"><b>${item[0]}</b>${item[1]}</a>`).join('')}<p>RAW PRESERVED<br>LOCAL / PRIVATE</p></aside><div class="review-document"><header class="review-document-head"><div><span class="eyebrow">PARSE & REVIEW</span><h1>Review before save.</h1><p>检查结构化结果。原始输入将完整保留。</p></div><button class="home-text-link" data-review-back>← 返回修改</button></header><section class="review-summary-paper" id="review-summary"><div class="review-summary-date"><span>ENTRY DATE</span><strong>${esc(summary.date||'缺失')}</strong></div>${reviewMetric('体重',summary.weight,'kg')}${reviewMetric('排便',summary.bowel_movement||'缺失')}${reviewMetric('热量',summary.calories,'kcal')}${reviewMetric('蛋白质',summary.protein,'g')}${reviewMetric('碳水',summary.carbs,'g')}${reviewMetric('脂肪',summary.fat,'g')}${reviewMetric('训练',summary.training||'缺失')}${reviewMetric('动作',summary.movement_count,'个')}${reviewMetric('有氧',summary.cardio||'缺失')}</section><section class="review-ledger-section" id="review-body"><header><span>02</span><h2>Body <small>身体</small></h2></header><div class="review-fields">${reviewInput('日期','date')}${reviewInput('体重 (kg)','body.weight',{type:'number'})}${reviewInput('排便','body.bowel_movement')}${reviewInput('训练部位','body.training_summary')}${reviewInput('有氧','body.cardio_summary',{wide:true})}${reviewInput('身体备注','body.notes',{wide:true,rows:2})}</div></section><section class="review-ledger-section" id="review-diet"><header><span>03</span><h2>Diet <small>饮食</small></h2></header><div class="review-fields review-macro-fields">${reviewInput('热量 (kcal)','diet.calories',{type:'number'})}${reviewInput('蛋白质 (g)','diet.protein',{type:'number'})}${reviewInput('碳水 (g)','diet.carbs',{type:'number'})}${reviewInput('脂肪 (g)','diet.fat',{type:'number'})}${reviewInput('饮食记录','diet.food_summary',{wide:true,rows:4})}${reviewInput('饮食备注','diet.notes',{wide:true,rows:2})}</div></section><section class="review-ledger-section" id="review-training"><header><span>04</span><h2>Training <small>训练</small></h2></header><div class="review-fields">${reviewInput('训练部位','training.split')}${reviewInput('标准摘要','training.standardized_summary',{wide:true,rows:2})}${reviewInput('训练备注','training.notes',{wide:true,rows:2})}</div></section><section class="review-ledger-section review-movements-section" id="review-movements"><header><span>05</span><h2>Movements <small>动作识别 · ${review.training?.movements?.length||0}</small></h2></header><div class="review-movement-list">${(review.training?.movements||[]).map((movement,index)=>movementReviewRow(movement,index,payload.mapping_options||[])).join('')||'<p class="empty-note">没有识别到训练动作。</p>'}</div></section><section class="review-ledger-section review-warning-section" id="review-warnings"><header><span>06</span><h2>Warnings <small>保存前检查</small></h2></header><div class="review-warning-list">${warnings.map(warning=>`<div class="review-warning ${esc(warning.severity)}"><b>${esc(warning.severity)}</b><span>${esc(warning.message)}</span></div>`).join('')||'<p class="review-clear">未发现明显问题。</p>'}</div>${duplicateCount?`<label class="duplicate-choice"><span>该日期已有 ${duplicateCount} 类记录，请选择保存方式</span><select id="review-save-mode"><option value="">保存时选择…</option><option value="overwrite">覆盖当天 Body / Diet / Training</option><option value="append_training">追加为同日第二次训练</option></select></label>`:''}</section></div><footer class="review-action-bar"><button class="btn btn-light" data-review-cancel>取消</button><button class="btn btn-light" data-review-back>← 返回修改</button><button class="btn btn-primary" data-review-save>确认并保存</button><small>原始文本保留 · 保存前自动备份</small></footer></section>`;window.scrollTo(0,0)}
const baseReviewPage=reviewPage;
reviewPage=function(payload){baseReviewPage(payload);const documentBody=$('.review-document'),head=$('.review-document-head'),movements=$('#review-movements'),index=$('.review-index');if(documentBody&&head&&movements){movements.classList.add('is-primary-review');head.insertAdjacentElement('afterend',movements)}if(index){const movementLink=index.querySelector('a[href="#review-movements"]'),firstLink=index.querySelector('a');if(movementLink&&firstLink)index.insertBefore(movementLink,firstLink);index.querySelectorAll('a').forEach((link,position)=>{const number=link.querySelector('b');if(number)number.textContent=String(position+1).padStart(2,'0')})}};
const reviewPageWithDuplicateStatus=reviewPage;
reviewPage=function(payload){reviewPageWithDuplicateStatus(payload);const choice=$('.duplicate-choice'),duplicates=payload.duplicates||{},count=Object.values(duplicates).reduce((sum,value)=>sum+Number(value||0),0);if(choice&&count){choice.outerHTML=`<div class="duplicate-status-card" role="status"><span class="duplicate-status-mark" aria-hidden="true">!</span><div><strong>该日期已有记录</strong><p>检测到 ${count} 条同日记录。确认保存时请选择覆盖现有内容，或仅追加本次训练。</p></div><small>保存前不会修改原记录</small></div>`}};
function collectReviewForm(){if(!state.reviewPayload)return null;$$('[data-review-field]').forEach(input=>setReviewValue(input.dataset.reviewField,input.type==='number'?(input.value===''?null:Number(input.value)):input.value));const movements=state.reviewPayload.review.training?.movements||[];movements.forEach((movement,index)=>{movement.display_name=$(`[data-movement-name="${index}"]`)?.value.trim()||movement.name;movement.notes=$(`[data-movement-note="${index}"]`)?.value.trim()||'';movement._review_action=$(`[data-movement-action="${index}"]`)?.value||'use';movement._mapped_movement_id=$(`[data-movement-map="${index}"]`)?.value||'';movement._muscle_group=$(`[data-movement-group="${index}"]`)?.value||''});return state.reviewPayload.review}
async function parseWebEntry(){const raw=$('#raw-entry')?.value.trim();if(!raw){showToast('请先输入每日记录。');return}state.draftRaw=raw;showToast('正在解析…');try{reviewPage(await postApi('/api/parse',{raw}))}catch(error){showToast(error.message||'解析失败。')}}
function updateSyncNav(){
  const nav=$('[data-sync-nav-entry]'),marker=nav?.querySelector('.sync-nav-status');
  if(!nav||!marker)return;
  const code=String(state.syncStatus?.sync_status||'').toUpperCase();
  const pending=['LOCAL_NEWER','LOCAL_CHANGES','READY'].includes(code);
  const failed=['UPLOAD_FAILED','CLOUD_MISMATCH','SYNC_ERROR'].includes(code);
  const visible=pending||failed;
  const copy=failed?'最近一次云同步未完成':'本地记录尚未同步到只读云副本';
  nav.hidden=!visible;
  marker.hidden=!visible;
  marker.className=`health-nav-status sync-nav-status${pending?' sync-pending':failed?' sync-error':''}`;
  if(!visible){marker.textContent='';nav.removeAttribute('title');nav.setAttribute('aria-label','查看云同步状态');return}
  marker.textContent=failed?'!':'•';
  nav.title=copy;
  nav.setAttribute('aria-label',copy);
}
function showSaveReceipt(result,error){const receipt=$('#save-receipt');if(!receipt)return;clearTimeout(state.receiptTimer);if(error){receipt.innerHTML=`<span>SAVE NEEDS ATTENTION</span><strong>${esc(error)}</strong>`}else if(result.status==='NO_CHANGES'){receipt.innerHTML='<span>NO CHANGES TO SAVE</span>'}else{const verb=result.status==='UPDATED'?'UPDATED':'SAVED',facts=[],date=result.date||result.record?.Date||result.history?.date||'';if(result.saved_movements)facts.push(`${result.saved_movements} movements · ${result.working_sets||0} working sets`);if(result.body_updated&&result.diet_updated)facts.push('Body and diet updated');else if(result.training_updated)facts.push('Training updated');receipt.innerHTML=`<span>${esc(String(date||'RECORD').toUpperCase())} ${verb}</span>${facts.map(x=>`<strong>${esc(x)}</strong>`).join('')}${state.syncStatus?.sync_status==='LOCAL_NEWER'?'<small>Cloud copy pending</small>':''}`};receipt.classList.add('is-visible');state.receiptTimer=setTimeout(()=>receipt.classList.remove('is-visible'),4200)}
async function refreshWebState(){[state.today,state.recent,state.body,state.diet,state.training,state.movements,state.dictionary,state.movementGroups,state.syncStatus]=await Promise.all([api('/api/today'),api('/api/recent?limit=5'),api('/api/body?limit=100'),api('/api/diet?limit=100'),api('/api/training?limit=100'),api('/api/movements?limit=100'),api('/api/dictionary'),api('/api/movement-groups'),api('/api/cloud-sync/status')]);updateSyncNav()}
async function saveWebReview(){if(state.saving)return;const review=collectReviewForm();if(!review)return;state.saving=true;const mode=$('#review-save-mode')?.value||null;const button=$('[data-review-save]');button.disabled=true;button.textContent='正在保存…';try{const result=await postApi('/api/save',{review_id:state.reviewPayload.review_id,review,save_mode:mode});if(result.status!=='NO_CHANGES'){state.reviewPayload=null;state.draftRaw=''}await refreshWebState();navigate('quick');showSaveReceipt(result)}catch(error){showSaveReceipt(null,error.message||'保存失败，原文件保持不变。');button.disabled=false;button.textContent='确认并保存';if(error.status===409){showToast('该日期已有记录，请选择覆盖或追加训练。');$('#review-save-mode')?.focus()}}finally{state.saving=false}}
function reviewDuplicateCount(){const duplicates=state.reviewPayload?.duplicates||{};return Object.values(duplicates).reduce((sum,value)=>sum+Number(value||0),0)}
function openSaveModeDialog(){document.querySelector('#save-mode-dialog')?.remove();document.body.insertAdjacentHTML('beforeend',`<dialog id="save-mode-dialog" class="save-mode-dialog" aria-labelledby="save-mode-title" aria-describedby="save-mode-copy"><form method="dialog" class="save-mode-sheet"><header><span class="eyebrow">SAVE DECISION / 同日记录</span><button class="save-mode-close" value="cancel" aria-label="关闭保存方式选择">×</button></header><div class="save-mode-heading"><span aria-hidden="true">!</span><div><h2 id="save-mode-title">该日期已有记录</h2><p id="save-mode-copy">请选择本次内容的保存方式。原记录会在你确认之前保持不变。</p></div></div><div class="save-mode-options"><button type="button" class="save-mode-option is-selective" data-save-mode-choice="append_training"><span><small>推荐</small><strong>选择性保存</strong></span><p>保留现有 Body 与 Diet，仅将本次训练作为同日另一条训练记录追加。</p><b aria-hidden="true">→</b></button><button type="button" class="save-mode-option is-overwrite" data-save-mode-choice="overwrite"><span><small>完整替换</small><strong>覆盖保存</strong></span><p>使用当前 Review 内容覆盖该日期已有的 Body、Diet 与 Training。</p><b aria-hidden="true">→</b></button></div><footer><button class="btn btn-light" value="cancel">取消 / 返回 Review</button><small>选择后才会执行保存；写入前仍沿用现有备份机制。</small></footer></form></dialog>`);const dialog=$('#save-mode-dialog');dialog.addEventListener('click',event=>{const option=event.target.closest('[data-save-mode-choice]');if(!option)return;const mode=option.dataset.saveModeChoice;dialog.close();saveWebReview(mode)});dialog.addEventListener('close',()=>dialog.remove(),{once:true});dialog.showModal();requestAnimationFrame(()=>dialog.querySelector('.is-selective')?.focus())}
saveWebReview=async function(saveMode=null){if(state.saving)return;const review=collectReviewForm();if(!review)return;if(reviewDuplicateCount()&&!saveMode){openSaveModeDialog();return}state.saving=true;const button=$('[data-review-save]');button.disabled=true;button.textContent='正在保存…';try{const result=await postApi('/api/save',{review_id:state.reviewPayload.review_id,review,save_mode:saveMode});if(result.status!=='NO_CHANGES'){state.reviewPayload=null;state.draftRaw=''}if(result.status!=='NO_CHANGES'&&(result.training_updated||Number(result.saved_movements||0)>0))invalidateMovementUsage();await refreshWebState();navigate('quick');showSaveReceipt(result)}catch(error){showSaveReceipt(null,error.message||'保存失败，原文件保持不变。');button.disabled=false;button.textContent='确认并保存';if(error.status===409){showToast('该日期已有记录，请重新选择保存方式。');openSaveModeDialog()}}finally{state.saving=false}};
const writableQuickPage=quickPage;
quickPage=function(){writableQuickPage();const textarea=$('#raw-entry');if(textarea&&state.draftRaw)textarea.value=state.draftRaw}

function dictionaryPage(){main.innerHTML=`<section class="page dictionary-page"><header class="dictionary-hero"><div><button class="dictionary-back" data-view="movements">← 返回 Movement Index</button><span class="eyebrow">07 / CONTROLLED VOCABULARY</span><h1>Movement<br>Dictionary</h1><p>管理标准名称、别名和训练部位。停用只会隐藏成长视图，仍可继续识别并记录。</p></div><button class="btn btn-primary" data-dictionary-new>+ 新建动作</button></header><div class="dictionary-toolbar"><input id="dictionary-search" class="control search" value="${esc(state.dictionaryQuery||'')}" placeholder="搜索名称、英文名、别名或 ID…"><select id="dictionary-status" class="control"><option value="all">全部状态</option><option value="focused">仅特别关注</option><option value="active">仅启用</option><option value="inactive">仅停用</option></select><span id="dictionary-count" class="result-count">正在读取…</span></div><div class="dictionary-sheet"><div class="dictionary-sheet-head"><span>状态</span><span>标准动作</span><span>训练部位</span><span>别名</span><span>历史</span><span>操作</span></div><div id="dictionary-rows"><div class="loading-page"><i></i><p>Reading movement dictionary…</p></div></div></div></section>`;loadDictionary()}

async function loadDictionary(){try{state.dictionary=await api('/api/dictionary');renderDictionary()}catch(error){const target=$('#dictionary-rows');if(target)target.innerHTML=`<div class="empty-copy"><h3>词典读取失败</h3><p>${esc(error.message)}</p></div>`}}

function renderDictionary(){const target=$('#dictionary-rows');if(!target)return;const query=($('#dictionary-search')?.value||'').trim().toLowerCase(),status=$('#dictionary-status')?.value||'all';const rows=state.dictionary.filter(item=>{const active=item.active!==false;if(status==='active'&&!active)return false;if(status==='inactive'&&active)return false;return !query||JSON.stringify(item).toLowerCase().includes(query)});target.innerHTML=rows.map(item=>{const active=item.active!==false,aliases=item.aliases||[];return `<article class="dictionary-row ${active?'':'is-inactive'}"><span class="dictionary-state ${active?'is-active':'is-inactive'}"><i></i>${active?'启用':'停用'}</span><div class="dictionary-name"><strong>${esc(item.display_name||'未命名')}</strong><small>${esc(item.english_name||item.movement_id||'')}</small><em>${esc(item.movement_id||'')}</em></div><span>${esc(groupLabel(item.muscle_group||'Unclassified'))}<small>${esc(item.category||'')}</small></span><div class="dictionary-aliases">${aliases.slice(0,4).map(alias=>`<b>${esc(alias)}</b>`).join('')}${aliases.length>4?`<small>+${aliases.length-4}</small>`:''}</div><span class="dictionary-history"><strong>${Number(item.history_count||0)}</strong><small>条记录</small></span><div class="dictionary-actions"><button class="home-text-link" data-dictionary-edit="${esc(item.movement_id)}">编辑</button><button class="home-text-link" data-dictionary-toggle="${esc(item.movement_id)}">${active?'停用':'启用'}</button><button class="home-text-link danger" data-dictionary-delete="${esc(item.movement_id)}">删除</button></div></article>`}).join('')||'<div class="empty-copy"><h3>没有匹配动作</h3><p>调整搜索词或状态筛选。</p></div>';const count=$('#dictionary-count');if(count)count.textContent=`${rows.length} / ${state.dictionary.length} movements`}

function dictionaryForm(item={}){const aliases=(item.aliases||[]).join('\n'),selected=item.muscle_group||'';return `<form id="dictionary-form" class="dictionary-form"><input type="hidden" name="movement_id" value="${esc(item.movement_id||'')}"><label><span>中文标准名 *</span><input name="display_name" value="${esc(item.display_name||'')}" required></label><label><span>英文名称</span><input name="english_name" value="${esc(item.english_name||'')}"></label><label><span>训练部位 *</span><select name="muscle_group" required><option value="">从已有部位中选择…</option>${movementGroupOptions(selected)}</select><small>部位决定动作分类；动作仍保持独立。</small></label><label><span>类别</span><input name="category" value="${esc(item.category||'Strength')}"></label><label><span>器械</span><input name="equipment" value="${esc(item.equipment||'')}"></label><label class="dictionary-pin"><span>特别关注</span><input type="checkbox" name="pinned" ${item.pinned||Number(item.focus_rank||0)>0?'checked':''}><small>开启后优先于普通动作显示</small></label><label><span>关注顺序</span><input type="number" min="0" step="1" name="focus_rank" value="${Number(item.focus_rank||0)}"><small>0 = 不关注；1 = 最高，2、3…依次降低</small></label><label class="is-wide"><span>别名（每行一个）</span><textarea name="aliases" rows="6">${esc(aliases)}</textarea><small>别名只用于识别同一个动作，不会改变训练部位。</small></label><label class="is-wide"><span>备注</span><textarea name="notes" rows="3">${esc(item.notes||'')}</textarea></label></form>`}

function openDictionaryEditor(movementId=''){const item=state.dictionary.find(row=>row.movement_id===movementId)||{},progress=movementId?`<section class="dictionary-progress-action"><div><span class="eyebrow">MOVEMENT PROGRESS / OPTIONAL</span><h3>不计入动作成长</h3><p>只从动作成长中隐藏，不影响训练记录和原始档案。</p></div><label class="dictionary-progress-switch"><input type="checkbox" data-movement-progress-exclusion="${esc(item.movement_id)}" ${item.exclude_from_progress?'checked':''}><span>${item.exclude_from_progress?'已从动作成长隐藏':'显示在动作成长'}</span></label></section>`:'',identity=item.is_custom===true?`<section class="dictionary-identity-action"><div><span class="eyebrow">CUSTOM / INDEPENDENT CANONICAL</span><h3>转为独立正式动作</h3><p>CUSTOM 动作会沿用独立转正流程；若只是已有动作的另一种叫法，请使用下方合并操作。</p></div><button class="btn" data-custom-merge-open="${esc(item.movement_id)}">改为合并已有动作 →</button></section>`:movementId?`<section class="dictionary-identity-action"><div><span class="eyebrow">ARCHIVE CONSOLIDATION / OPTIONAL</span><h3>合并到其他动作</h3><p>仅在两个正式动作确为同一动作时使用。系统会先展示 Core 的迁移计划，再由你明确确认。</p></div><button class="btn" data-movement-merge-open="${esc(item.movement_id)}">合并到其他动作 →</button></section>`:'';modal(movementId?'编辑动作词典':'新建动作词典',dictionaryForm(item)+progress+identity,{light:true,actions:`<button class="btn" data-close>取消</button><button class="btn btn-primary" data-dictionary-save="${esc(movementId)}">${item.is_custom===true?'保存并转为独立正式动作':'保存词典'}</button>`})}

function collectDictionaryForm(){const form=$('#dictionary-form');if(!form)return null;const data=Object.fromEntries(new FormData(form).entries());data.aliases=String(data.aliases||'').split(/\r?\n|,|，|;|；/).map(value=>value.trim()).filter(Boolean);data.focus_rank=Math.max(0,Number(data.focus_rank||0));data.pinned=form.elements.pinned?.checked===true||data.focus_rank>0;return data}

async function saveDictionaryForm(movementId){const definition=collectDictionaryForm();if(!definition?.display_name?.trim()){showToast('中文标准名不能为空。');return}if(!definition?.muscle_group){showToast('请从已有部位中选择训练部位。');return}const item=state.dictionary.find(row=>row.movement_id===movementId),promoting=item?.is_custom===true,button=$('[data-dictionary-save]');button.disabled=true;try{const result=await postApi(promoting?'/api/movements/custom-promote':movementId?'/api/dictionary/update':'/api/dictionary/create',promoting?{source_id:movementId,definition}:movementId?{movement_id:movementId,definition}:definition);root.innerHTML='';if(result.status!=='NO_CHANGES')invalidateMovementUsage();await Promise.all([loadDictionary(),refreshWebState(),loadArchiveHealth()]);renderDictionary();showToast(promoting?`“${result.display_name}”已成为 ${groupLabel(result.muscle_group)} 下的独立正式动作。`:`动作词典已保存；归并 ${Number(result.reconciliation?.merged_history||0)+Number(result.reconciliation?.restored_skipped||0)} 条历史。`)}catch(error){button.disabled=false;showToast(error.message||'词典保存失败。')}}
async function setMovementProgressExclusion(movementId,excluded){const control=$(`[data-movement-progress-exclusion="${CSS.escape(movementId)}"]`);if(control)control.disabled=true;try{const result=await postApi('/api/movements/progress-exclusion',{movement_id:movementId,excluded});if(result.status!=='NO_CHANGES')invalidateMovementUsage();await Promise.all([loadDictionary(),refreshWebState()]);const updated=state.dictionary.find(item=>item.movement_id===movementId);if(updated)openDictionaryEditor(movementId);renderDictionary();showToast(result.status==='NO_CHANGES'?'动作成长显示状态未变化。':excluded?'该动作已从动作成长隐藏；训练档案仍完整保留。':'该动作已恢复到动作成长。')}catch(error){if(control)control.checked=!excluded;showToast(error.message||'动作成长显示状态更新失败。')}finally{if(control)control.disabled=false}}

async function toggleDictionaryEntry(movementId){const item=state.dictionary.find(row=>row.movement_id===movementId);if(!item)return;try{const result=await postApi('/api/dictionary/active',{movement_id:movementId,active:item.active===false});if(result.status!=='NO_CHANGES')invalidateMovementUsage();await Promise.all([loadDictionary(),refreshWebState()]);renderDictionary();showToast(item.active===false?'动作已启用。':'动作已停用；历史仍会保留并继续记录。')}catch(error){showToast(error.message||'状态更新失败。')}}

function confirmDictionaryDelete(movementId){const item=state.dictionary.find(row=>row.movement_id===movementId);if(!item)return;modal('删除动作词典',`<div class="dictionary-delete-warning"><span class="eyebrow">DESTRUCTIVE ACTION</span><p>将删除 <strong>${esc(item.display_name)}</strong> 的词典项及 <strong>${Number(item.history_count||0)}</strong> 条结构化动作历史。每日原始输入不会删除。</p><label class="field"><span>输入“${esc(item.display_name)}”确认</span><input id="dictionary-delete-confirm" autocomplete="off"></label></div>`,{light:true,actions:`<button class="btn" data-close>取消</button><button class="btn btn-danger" data-dictionary-delete-confirm="${esc(movementId)}">确认删除</button>`})}

async function deleteDictionaryEntry(movementId){const confirmation=$('#dictionary-delete-confirm')?.value||'';try{const result=await postApi('/api/dictionary/delete',{movement_id:movementId,confirmation});root.innerHTML='';if(result.status!=='NO_CHANGES')invalidateMovementUsage();await Promise.all([loadDictionary(),refreshWebState()]);renderDictionary();showToast(`已删除 ${result.display_name} 及 ${result.deleted_history} 条结构化历史。`)}catch(error){showToast(error.message||'删除失败。')}}

function movementMergeNotice(item){return typeof item==='string'?item:String(item?.message||item?.code||'需要检查迁移计划。')}
function movementMergeCandidates(query=''){const flow=state.movementMerge,needle=String(query||'').trim().toLowerCase();if(!flow)return[];return flow.candidates.filter(item=>!needle||[item.display_name,item.english_name,item.movement_id,...(item.aliases||[])].join(' ').toLowerCase().includes(needle))}
function movementMergeCandidateRows(query=''){const rows=movementMergeCandidates(query);return rows.map(item=>`<button class="movement-merge-candidate ${state.movementMerge?.target?.movement_id===item.movement_id?'is-selected':''}" data-custom-merge-target="${esc(item.movement_id)}"><span><strong>${esc(item.display_name)}</strong>${item.english_name?`<small>${esc(item.english_name)}</small>`:''}</span><code>${esc(item.movement_id)}</code><em>${esc(groupLabel(item.muscle_group||'Unclassified'))}</em><b>${Number(item.history_count||0)} 条历史</b></button>`).join('')||'<div class="movement-merge-empty"><strong>没有匹配的正式动作</strong><p>调整搜索词；这里只会显示已有的非 CUSTOM 正式动作。</p></div>'}
function movementMergeIdentity(source,target){const type=state.movementMerge?.kind==='custom'?'CUSTOM':'FORMAL';return `<div class="movement-merge-identity"><article><span>SOURCE / ${type}</span><strong>${esc(source?.display_name||'—')}</strong><code>${esc(source?.movement_id||'—')}</code></article><b aria-hidden="true">→</b><article class="is-target"><span>TARGET / CANONICAL</span><strong>${esc(target?.display_name||'请选择正式动作')}</strong><code>${esc(target?.movement_id||'尚未选择')}</code></article></div>`}
function movementMergePlanHtml(plan){const history=plan.history||{},references=plan.references||{},aliases=plan.aliases||{},raw=plan.raw||{},duplicates=plan.duplicates||{},warnings=plan.warnings||[],blockers=plan.blockers||[],source=plan.source||state.movementMerge?.source,target=plan.target||state.movementMerge?.target,custom=state.movementMerge?.kind==='custom';return `<section class="movement-merge-plan">${movementMergeIdentity(source,target)}<div class="movement-merge-impact"><article><span>Source 历史</span><strong>${Number(history.source_history_count||0)}</strong></article><article><span>Target 当前</span><strong>${Number(history.target_history_count||0)}</strong></article><article><span>迁移后历史</span><strong>${Number(history.target_history_after||0)}</strong></article><article><span>迁移引用</span><strong>${Number(references.migratable_count||0)}</strong></article><article><span>涉及训练日</span><strong>${(history.dates||[]).length}</strong></article></div><section class="movement-merge-paper"><span class="eyebrow">NAME COMPATIBILITY</span><h3>旧名称将继续被识别</h3><div class="movement-merge-aliases">${(aliases.to_add||[]).map(alias=>`<span>${esc(alias)}</span>`).join('')||'<small>无需新增 alias</small>'}</div></section><section class="movement-merge-audit"><div><span class="eyebrow">DUPLICATES / PRESERVE ALL</span><p>完全重复 ${Number((duplicates.exact_content||[]).length)} · 同日 ${Number((duplicates.same_dates||[]).length)} · 同训练日 ${Number((duplicates.same_training_days||[]).length)}</p><small>Core 会保留全部历史，不会自动去重。</small></div><div><span class="eyebrow">RAW / SKIPPED AUDIT</span><p>Skipped 匹配 ${Number((raw.skipped_source_matches||[]).length)} · 原始文本保持不变</p><small>${esc(raw.migration_plan||'原始录入文本不会被重新解析。')}</small></div></section>${warnings.length?`<section class="movement-merge-notices is-warning"><span class="eyebrow">需要注意</span>${warnings.map(item=>`<p><b>${esc(item.code||'WARNING')}</b>${esc(movementMergeNotice(item))}</p>`).join('')}</section>`:''}${blockers.length?`<section class="movement-merge-notices is-blocked"><span class="eyebrow">阻塞问题</span>${blockers.map(item=>`<p><b>${esc(item.code||'BLOCKED')}</b>${esc(movementMergeNotice(item))}</p>`).join('')}</section>`:''}<section class="movement-merge-confirm ${plan.can_execute?'':'is-disabled'}"><div><span class="eyebrow">FINAL CONFIRMATION</span><h3>${esc(source?.display_name||'—')} → ${esc(target?.display_name||'—')}</h3><p><code>${esc(source?.movement_id||'—')}</code> 将归入 <code>${esc(target?.movement_id||'—')}</code>；历史 ${Number(history.source_history_count||0)} + ${Number(history.target_history_count||0)} → ${Number(history.target_history_after||0)}。</p></div><button class="btn btn-primary" data-custom-merge-execute ${!plan.can_execute||!plan.plan_identity?'disabled':''}>${custom?'确认转为正式动作':'确认合并动作'}</button></section></section>`}
function renderMovementMergeFlow(){const flow=state.movementMerge;if(!flow)return;const selected=flow.target,preview=flow.preview,error=flow.error,custom=flow.kind==='custom',title=custom?'转为正式动作':'合并到其他动作',copy=custom?'选择一个已有正式动作，先查看 Core 生成的迁移计划，再明确确认。':'选择一个已有、有效且启用的正式动作。Core 会先生成只读迁移计划；不会自动去重。';root.innerHTML=`<div class="overlay movement-merge-overlay"><section class="movement-merge-modal" role="dialog" aria-modal="true" aria-labelledby="movement-merge-title"><button class="close" data-custom-merge-close aria-label="关闭${title}">×</button><header><span class="eyebrow">MOVEMENT DEFINITION / ARCHIVE IDENTITY</span><h2 id="movement-merge-title">${title}</h2><p>${copy}</p></header>${error?`<div class="movement-merge-error"><strong>${esc(error.title||'无法继续')}</strong><p>${esc(error.message||'请重新检查迁移预览。')}</p></div>`:''}${preview?movementMergePlanHtml(preview):`<section class="movement-merge-selector">${movementMergeIdentity(flow.source,selected)}<label><span>搜索正式动作</span><input id="movement-merge-search" type="search" autocomplete="off" placeholder="中文名、英文名或 alias…"></label><div class="movement-merge-candidates" id="movement-merge-candidates">${movementMergeCandidateRows()}</div><footer><small>候选来自正式动作词典；不能手工输入 movement_id。</small><button class="btn btn-primary" data-custom-merge-preview ${!selected||flow.loading?'disabled':''}>${flow.loading?'正在生成预览…':error?.code==='PREVIEW_STALE'||error?.code==='PREVIEW_REQUIRED'?'重新生成预览 →':'检查迁移计划 →'}</button></footer></section>`}${preview?`<footer class="movement-merge-plan-actions"><button class="btn" data-custom-merge-back>重新选择正式动作</button></footer>`:''}</section></div>`;requestAnimationFrame(()=>$('#movement-merge-search')?.focus())}
async function openMovementMerge(sourceId,kind='formal'){const source=state.dictionary.find(item=>item.movement_id===sourceId&&(kind==='custom'?item.is_custom===true:item.is_custom!==true));if(!source){showToast(kind==='custom'?'只有正式识别的 CUSTOM 动作可以转为正式动作。':'只能从现有正式动作开始合并。');return}state.movementMerge={kind,source,candidates:[],target:null,preview:null,error:null,loading:true,submitting:false};root.innerHTML='<div class="overlay movement-merge-overlay"><section class="movement-merge-modal is-loading"><button class="close" data-custom-merge-close>×</button><div class="movement-merge-loading"><i></i><p>正在读取正式动作候选…</p></div></section></div>';try{const candidateApi=kind==='custom'?'/api/movements/canonical-candidates':'/api/movements/merge-candidates';state.movementMerge.candidates=await api(`${candidateApi}?source_id=${encodeURIComponent(sourceId)}`);state.movementMerge.loading=false;renderMovementMergeFlow()}catch(error){state.movementMerge=null;root.innerHTML='';showToast(error.message||'无法读取正式动作候选。')}}
function openCustomMovementMerge(sourceId){return openMovementMerge(sourceId,'custom')}
function selectCustomMovementTarget(targetId){const flow=state.movementMerge,target=flow?.candidates.find(item=>item.movement_id===targetId);if(!flow||!target)return;flow.target=target;flow.preview=null;flow.error=null;renderMovementMergeFlow()}
async function previewCustomMovementMerge(){const flow=state.movementMerge;if(!flow?.target||flow.loading)return;flow.loading=true;flow.error=null;renderMovementMergeFlow();try{flow.preview=await postApi(flow.kind==='custom'?'/api/movements/custom-merge/preview':'/api/movements/merge/preview',{source_id:flow.source.movement_id,target_id:flow.target.movement_id});flow.loading=false;renderMovementMergeFlow()}catch(error){flow.loading=false;flow.preview=null;flow.error={code:error.payload?.code,title:'无法生成迁移预览',message:error.message};renderMovementMergeFlow()}}
function renderMovementMergeFailure(error){const flow=state.movementMerge,details=error.payload?.details||{},rollbackErrors=details.rollback_errors||[],rolledBack=details.rolled_back===true;root.innerHTML=`<div class="overlay movement-merge-overlay"><section class="movement-merge-modal movement-merge-result is-failed" role="dialog" aria-modal="true"><button class="close" data-custom-merge-close>×</button><span class="eyebrow">MIGRATION NOT COMPLETED</span><h2>迁移未完成</h2><p>${rolledBack&&rollbackErrors.length===0?'档案已恢复到迁移前状态。':'无法确认完整回滚，请进入 Data Check 检查档案状态。'}</p><div class="movement-merge-result-actions"><button class="btn" data-custom-merge-close>关闭</button>${!rolledBack||rollbackErrors.length?'<button class="btn btn-primary" data-custom-merge-data-check>进入 Data Check →</button>':''}</div></section></div>`;if(flow)flow.submitting=false}
function renderMovementMergeSuccess(result,source,target){const title=state.movementMerge?.kind==='custom'?'已转为正式动作':'动作已合并';root.innerHTML=`<div class="overlay movement-merge-overlay"><section class="movement-merge-modal movement-merge-result is-success" role="dialog" aria-modal="true"><button class="close" data-custom-merge-close>×</button><span class="eyebrow">CANONICAL MOVEMENT / COMPLETE</span><h2>${title}</h2>${movementMergeIdentity(source,target)}<div class="movement-merge-impact"><article><span>迁移历史</span><strong>${Number(result.migrated_history_count||0)}</strong></article><article><span>迁移引用</span><strong>${Number(result.migrated_reference_count||0)}</strong></article><article><span>Target 历史</span><strong>${Number(result.target_history_after||0)}</strong></article><article><span>新增 aliases</span><strong>${Number((result.aliases_added||[]).length)}</strong></article></div><div class="movement-merge-result-copy"><p><b>原始录入文本</b>${result.raw_entries_unchanged?'保持不变':'需要检查'}</p><p><b>迁移验证</b>${result.validation?.ok?'已通过':'需要检查'}</p><p><b>Undo</b>${result.undo?.available?'可通过现有回退能力恢复':'当前不可用'}</p></div><div class="movement-merge-result-actions"><button class="btn btn-primary" data-custom-merge-target-open>查看正式动作 →</button></div></section></div>`}
async function executeCustomMovementMerge(){const flow=state.movementMerge,plan=flow?.preview;if(!flow||flow.submitting||!plan?.can_execute||!plan.plan_identity)return;flow.submitting=true;const button=$('[data-custom-merge-execute]');if(button){button.disabled=true;button.textContent='正在迁移并验证…'}try{const source=flow.source,target=flow.target,result=await postApi(flow.kind==='custom'?'/api/movements/custom-merge/execute':'/api/movements/merge/execute',{source_id:source.movement_id,target_id:target.movement_id,plan_identity:plan.plan_identity});invalidateMovementUsage();await Promise.all([loadDictionary(),refreshWebState(),loadArchiveHealth()]);navigate('movements',{movement_id:result.target_id});renderMovementMergeSuccess(result,source,target)}catch(error){const code=error.payload?.code;if(code==='PREVIEW_STALE'||code==='PREVIEW_REQUIRED'){flow.submitting=false;flow.preview=null;flow.error={code,title:'档案数据已变化',message:'请重新检查迁移预览后再次确认。'};renderMovementMergeFlow();return}if(code==='MIGRATION_BLOCKED'){flow.submitting=false;flow.preview={...plan,can_execute:false,blockers:error.payload?.details?.blockers||plan.blockers||[]};flow.error={code,title:'当前计划存在阻塞问题',message:'请查看 Core 返回的 blocker，或返回重新选择正式动作。'};renderMovementMergeFlow();return}if(code==='MIGRATION_FAILED'){renderMovementMergeFailure(error);return}flow.submitting=false;flow.error={code,title:'迁移未完成',message:error.message||'请重新检查迁移计划。'};renderMovementMergeFlow()}}
function closeCustomMovementMerge(){state.movementMerge=null;root.innerHTML=''}

renderDictionary=function(){
  const target=$('#dictionary-rows');if(!target)return;
  const query=($('#dictionary-search')?.value||'').trim().toLowerCase(),status=$('#dictionary-status')?.value||'all';
  const rows=state.dictionary.filter(item=>{const active=item.active!==false;if(status==='active'&&!active)return false;if(status==='inactive'&&active)return false;if(status==='focused'&&!item.pinned)return false;return !query||JSON.stringify(item).toLowerCase().includes(query)});
  const head=$('.dictionary-sheet-head');if(head)head.innerHTML='<span>状态</span><span>标准动作</span><span>训练部位</span><span>历史</span><span>操作</span>';
  target.innerHTML=rows.map(item=>{const active=item.active!==false,progressExcluded=item.exclude_from_progress===true;return `<article class="dictionary-row dictionary-row-compact ${active?'':'is-inactive'} ${item.pinned?'is-focused':''} ${progressExcluded?'is-progress-excluded':''}"><span class="dictionary-state ${active?'is-active':'is-inactive'}"><i></i>${item.pinned?'★ 关注':active?'启用':'停用'}</span><div class="dictionary-name"><strong>${esc(item.display_name||'未命名')}</strong><small>${esc(item.english_name||item.movement_id||'')}</small>${progressExcluded?'<em class="dictionary-progress-note">不计入成长</em>':''}</div><span class="dictionary-group">${esc(groupLabel(item.muscle_group||'Unclassified'))}</span><span class="dictionary-history"><strong>${Number(item.history_count||0)}</strong><small>条</small></span><div class="dictionary-actions dictionary-icon-actions"><button title="编辑动作" aria-label="编辑 ${esc(item.display_name)}" data-dictionary-edit="${esc(item.movement_id)}"><b>✎</b><span>编辑</span></button><button title="${active?'停用动作':'启用动作'}" aria-label="${active?'停用':'启用'} ${esc(item.display_name)}" data-dictionary-toggle="${esc(item.movement_id)}"><b>${active?'◐':'●'}</b><span>${active?'停用':'启用'}</span></button><button class="danger" title="删除动作" aria-label="删除 ${esc(item.display_name)}" data-dictionary-delete="${esc(item.movement_id)}"><b>×</b><span>删除</span></button></div></article>`}).join('')||'<div class="empty-copy"><h3>没有匹配动作</h3><p>调整搜索词或状态筛选。</p></div>';
  const count=$('#dictionary-count');if(count)count.textContent=`${rows.length} / ${state.dictionary.length} movements`;
};

function parseRoute(){const raw=location.hash.slice(1)||'home',separator=raw.indexOf('?'),view=separator<0?raw:raw.slice(0,separator);return {view:view||'home',params:new URLSearchParams(separator<0?'':raw.slice(separator+1))}}
function routeHash(view,params={}){const query=new URLSearchParams(Object.entries(params).filter(([,value])=>value!==undefined&&value!==null&&value!==''));const suffix=query.toString();return `#${view}${suffix?`?${suffix}`:''}`}
function resetRouteUiState(){state.selectedBodyPart=null;state.trainingQuery='';state.trainingOrder='recent';state.movementSelection='';state.movementQuery=''}
function renderRoute(route=parseRoute(),entryState=history.state||{}){const legacy=route.view==='checks'?'health':route.view==='export'?'export':route.view==='cloud-sync'?'sync':'';if(legacy)route={view:'tools',params:new URLSearchParams({panel:legacy})};state.view=route.view;state.routeParams=Object.fromEntries(route.params);state.routeState=entryState;resetRouteUiState();$$('.nav-item').forEach(b=>b.classList.toggle('is-active',b.dataset.view===state.view));window.scrollTo(0,0);({home:homePage,quick:quickPage,body:bodyPage,diet:dietPage,training:trainingPage,movements:movementPage,checks:checksPage,dictionary:dictionaryPage,tools:toolsPage}[state.view]||homePage)();if(legacy==='health')queueMicrotask(openDataCheckOverlay)}
async function load(){try{await refreshWebState();const route=parseRoute();history.replaceState({view:route.view},'',location.href);renderRoute(route,history.state||{});void loadArchiveHealth()}catch(e){main.innerHTML=`<div class="loading-page"><h2>Local data service unavailable</h2><p>${esc(e.message)}</p></div>`}}
function navigate(v,params={},options={}){const legacy=v==='checks'?'health':v==='export'?'export':v==='cloud-sync'?'sync':'';if(legacy){v='tools';params={...params,panel:legacy}}const entry={view:v},hash=routeHash(v,params);if(options.replace)history.replaceState(entry,'',hash);else history.pushState(entry,'',hash);renderRoute({view:v,params:new URLSearchParams(Object.entries(params))},entry)}
function openMovementFromTraining(movementId){const id=String(movementId||'').trim();if(!id)return;navigate('movements',{movement_id:id})}
function openTrainingFromMovement(entryDate,movementId){const date=String(entryDate||'').slice(0,10),id=String(movementId||'').trim();if(!date)return;navigate('training',{date,movement_id:id})}
document.addEventListener('click',event=>{const target=event.target.closest('button,a');if(!target)return;if(target.id==='parse'){event.preventDefault();event.stopImmediatePropagation();parseWebEntry();return}if(target.dataset.reviewSave!==undefined){event.preventDefault();event.stopImmediatePropagation();saveWebReview();return}if(target.dataset.reviewBack!==undefined){event.preventDefault();event.stopImmediatePropagation();navigate('quick');return}if(target.dataset.reviewCancel!==undefined){event.preventDefault();event.stopImmediatePropagation();state.reviewPayload=null;state.draftRaw='';navigate('quick');return}if(target.matches('.review-index a')){event.preventDefault();event.stopImmediatePropagation();document.querySelector(target.getAttribute('href'))?.scrollIntoView({behavior:'smooth',block:'start'})}},true);
document.addEventListener('change',event=>{const action=event.target.closest('[data-movement-action]');if(!action)return;const index=action.dataset.movementAction,mapping=$(`[data-movement-map="${index}"]`),group=$(`[data-movement-group="${index}"]`);if(mapping)mapping.disabled=action.value!=='map';if(group)group.disabled=action.value!=='add'});
document.addEventListener('click',e=>{const b=e.target.closest('button,[data-detail],[data-movement],[data-issue]');if(!b)return;if(b.dataset.dataCheckOpen!==undefined){e.preventDefault();openDataCheckOverlay();return}else if(b.dataset.view)navigate(b.dataset.view,{},b.classList.contains('nav-item')?{context:null}:{});if(b.dataset.go)navigate(b.dataset.go,{},{});if(b.dataset.close!==undefined){state.dataCheckOverlayOpen=false;root.innerHTML='';return}if(b.dataset.mock)showToast(b.dataset.mock);if(b.dataset.record)recordDetail(b.dataset.record);if(b.dataset.detail)detail(b.dataset.detail,Number(b.dataset.index));if(b.dataset.movementIndex!==undefined)navigate('movements',{},{});else if(b.dataset.selectMovementId)openMovementFromTraining(b.dataset.selectMovementId);else if(b.dataset.movement)movementDetail(b.dataset.movement);if(b.dataset.issue!==undefined)modal('Issue detail',`<span class="severity ${issues[b.dataset.issue][0].toLowerCase()}">${issues[b.dataset.issue][0]}</span><div class="detail-list"><div class="detail-row"><label>Date</label><div>${issues[b.dataset.issue][1]}</div></div><div class="detail-row"><label>Area</label><div>${issues[b.dataset.issue][2]}</div></div><div class="detail-row"><label>Issue</label><div>${issues[b.dataset.issue][3]}</div></div></div>`,{actions:'<button class="btn btn-primary" data-mock="Open action is a UI preview.">Take action →</button>'});if(b.id==='parse')reviewPage($('#raw-entry').value);if(b.dataset.back!==undefined)navigate('quick');if(b.dataset.duplicate!==undefined)duplicate();if(b.dataset.approval!==undefined)approval();if(b.dataset.drawer)drawer(b.dataset.drawer)});
