function issueCounts(rows){return rows.reduce((counts,item)=>{const key=String(item.severity||'').toLowerCase();counts[key]=(counts[key]||0)+1;return counts},{})}
function issueCanRepair(item){return ['body','diet','training','movement','dictionary','raw'].includes(String(item.target_type||''))}
function issueIsCustomIdentity(item){return /CUSTOM|未标准化动作|尚未确认正式身份|转为独立正式动作/i.test(`${item.issue||''} ${item.action||''}`)}
function issueActionButtons(item,index){
  const type=String(item.target_type||'');
  const buttons=[`<button class="link issue-open" data-real-issue="${index}">详情</button>`];
  if(issueIsCustomIdentity(item))buttons.push(`<button class="link issue-repair issue-primary-action" data-issue-repair="${index}" data-repair-action="dictionary-custom">查看待转正动作 →</button>`);
  else if(['body','diet','training'].includes(type))buttons.push(`<button class="link issue-repair issue-primary-action" data-issue-repair="${index}" data-repair-action="editor">去修复 →</button>`,`<button class="link issue-repair" data-issue-repair="${index}" data-repair-action="record">查看记录</button>`);
  else if(type==='movement')buttons.push(`<button class="link issue-repair" data-issue-repair="${index}" data-repair-action="movement">动作轨迹</button>`,`<button class="link issue-repair" data-issue-repair="${index}" data-repair-action="dictionary">动作词典</button>`);
  else if(type==='dictionary')buttons.push(`<button class="link issue-repair issue-primary-action" data-issue-repair="${index}" data-repair-action="dictionary">打开动作词典 →</button>`);
  else if(type==='raw')buttons.push(`<button class="link issue-repair" data-issue-repair="${index}" data-repair-action="raw">原始输入</button>`);
  if(/cloud|payload|sync/i.test(`${item.issue||''} ${item.area||''}`))buttons.push(`<button class="link issue-repair" data-issue-repair="${index}" data-repair-action="cloud">云同步</button>`);
  buttons.push(`<button class="link issue-ack" data-issue-ack="${index}">确认问题</button>`);
  return buttons.join('');
}
function dataCheckSurfaceHtml(rows,{overlay=false,acknowledged=0}={}){
  const counts=issueCounts(rows);
  return `<div class="data-check-surface ${overlay?'is-overlay':''}" data-check-surface><div class="toolbar check-filters"><button class="btn btn-primary is-selected" data-check-filter="all">全部问题 &nbsp; ${rows.length}</button><button class="btn" data-check-filter="high">高 ${counts.high||0}</button><button class="btn" data-check-filter="medium">中 ${counts.medium||0}</button><button class="btn" data-check-filter="low">低 ${counts.low||0}</button></div><div class="table-wrap check-table-wrap"><table class="check-table"><thead><tr><th>级别</th><th>日期</th><th>区域</th><th>问题与建议</th><th>操作</th></tr></thead><tbody>${rows.map((item,index)=>`<tr data-severity="${esc(String(item.severity).toLowerCase())}"><td><span class="severity ${esc(String(item.severity).toLowerCase())}">${esc(item.severity)}</span></td><td>${esc(item.date)}</td><td>${esc(item.area)}</td><td class="issue-copy"><strong>${esc(item.issue)}</strong><small>${esc(item.action)}</small></td><td><div class="issue-actions">${issueActionButtons(item,index)}</div></td></tr>`).join('')}</tbody></table>${rows.length?'':'<div class="data-check-empty"><strong>当前没有待处理问题</strong><p>Review 入口将自动保持静默。</p></div>'}</div><div class="records-status" aria-live="polite">显示 ${rows.length} 个未确认问题 · 已隐藏 ${acknowledged} 个</div></div>`;
}
function renderDataCheckOverlay(payload){
  const rows=payload?.issues||[];
  root.innerHTML=`<div class="overlay data-check-overlay-shell" data-data-check-overlay><section class="data-check-overlay" role="dialog" aria-modal="true" aria-labelledby="data-check-overlay-title"><button class="close" data-data-check-close aria-label="关闭 Data Check">×</button><header><span class="eyebrow">SILENT HEALTH / REVIEW</span><h2 id="data-check-overlay-title">Data Check</h2><p>只在需要处理时出现。查看、修正或确认后，你会回到当前档案页面。</p></header>${dataCheckSurfaceHtml(rows,{overlay:true,acknowledged:payload?.acknowledged_count||0})}<aside class="data-check-overlay-detail" data-data-check-detail hidden></aside></section></div>`;
}
async function openDataCheckOverlay(){
  state.dataCheckOverlayOpen=true;
  root.innerHTML='<div class="overlay data-check-overlay-shell" data-data-check-overlay><section class="data-check-overlay is-loading" role="dialog" aria-modal="true"><button class="close" data-data-check-close aria-label="关闭 Data Check">×</button><div class="loading-page"><i></i><p>正在读取待处理问题…</p></div></section></div>';
  try{state.dataCheck=await api('/api/data-check');renderDataCheckOverlay(state.dataCheck)}catch(error){root.innerHTML=`<div class="overlay data-check-overlay-shell" data-data-check-overlay><section class="data-check-overlay is-unavailable" role="dialog" aria-modal="true"><button class="close" data-data-check-close aria-label="关闭 Data Check">×</button><span class="eyebrow">SILENT HEALTH / UNAVAILABLE</span><h2>Data Check 暂不可用</h2><p>${esc(error.message||'本地检查服务没有返回有效结果。')}</p></section></div>`}
}
function closeDataCheckOverlay(){state.dataCheckOverlayOpen=false;root.innerHTML=''}
checksPage=async function(){
  main.innerHTML='<div class="loading-page"><i></i><p>正在读取本地数据检查结果…</p></div>';
  try{
    state.dataCheck=await api('/api/data-check');
    const rows=state.dataCheck.issues||[];
    main.innerHTML=`<section class="page page-grid checks-page"><div class="content">${pageHeader('Data Check','兼容视图：真实扫描本地记录，不会自动改写数据。')}${dataCheckSurfaceHtml(rows,{acknowledged:state.dataCheck.acknowledged_count||0})}</div><aside class="rail"><section class="rail-section" style="margin-top:0"><span class="eyebrow">处理原则</span><h2 style="font:400 24px var(--serif)">定位、修正、再确认</h2><p>检查只提供定位，不会自动修改正式记录。</p></section></aside></section>`;
  }catch(error){main.innerHTML=`<div class="loading-page"><h2>Data Check unavailable</h2><p>${esc(error.message)}</p></div>`}
}

function openRealIssue(index){
  const issue=state.dataCheck?.issues?.[index];if(!issue)return;
  const custom=issueIsCustomIdentity(issue);
  const detail=$('[data-data-check-detail]');
  if(state.dataCheckOverlayOpen&&detail){detail.hidden=false;detail.innerHTML=`<button class="data-check-detail-close" data-data-check-detail-close aria-label="关闭问题详情">×</button><span class="severity ${esc(String(issue.severity).toLowerCase())}">${esc(issue.severity)}</span><h3>问题详情</h3><div class="detail-list"><div class="detail-row"><label>日期</label><div>${esc(issue.date)}</div></div><div class="detail-row"><label>区域</label><div>${esc(issue.area)}</div></div><div class="detail-row"><label>具体问题</label><div>${esc(issue.issue)}</div></div><div class="detail-row"><label>建议处理</label><div>${esc(issue.action)}</div></div></div><div class="modal-actions"><button class="btn" data-issue-ack="${index}">确认并隐藏</button><button class="btn btn-primary" data-issue-repair="${index}" data-repair-action="${custom?'dictionary-custom':'editor'}">${custom?'去整理 CUSTOM 动作':'前往处理'} →</button></div>`;return}
  modal('问题详情',`<span class="severity ${esc(String(issue.severity).toLowerCase())}">${esc(issue.severity)}</span><div class="detail-list"><div class="detail-row"><label>日期</label><div>${esc(issue.date)}</div></div><div class="detail-row"><label>区域</label><div>${esc(issue.area)}</div></div><div class="detail-row"><label>具体问题</label><div>${esc(issue.issue)}</div></div><div class="detail-row"><label>建议处理</label><div>${esc(issue.action)}</div></div></div>`,{actions:`<button class="btn" data-issue-ack="${index}">确认并隐藏</button><button class="btn btn-primary" data-issue-repair="${index}" data-repair-action="${custom?'dictionary-custom':'editor'}">${custom?'去整理 CUSTOM 动作':'前往处理'} →</button>`});
}

function repairIssue(index,action='editor'){
  const issue=state.dataCheck?.issues?.[index];if(!issue)return;
  closeDataCheckOverlay();state.repairReturn=true;
  if(action==='cloud'){navigate('cloud-sync');return}
  if(action==='record'){recordDetail(issue.date);return}
  if(action==='raw'){recordDetail(issue.date);return}
  if(action==='dictionary-custom'){state.dictionaryQuery='CUSTOM_';navigate('dictionary');return}
  if(action==='dictionary'){state.dictionaryQuery=issue.movement_name||issue.search_term||'';navigate('dictionary');return}
  if(['body','diet','training'].includes(issue.target_type)){
    const rows={body:state.body,diet:state.diet,training:state.training}[issue.target_type]||[];
    const recordIndex=rows.findIndex(row=>String(row.id||'')===String(issue.target_id||'')||(dateOf(row)===issue.date&&!issue.target_id));
    if(recordIndex>=0){realRecordDetail(issue.target_type,recordIndex);return}
    navigate(issue.target_type);return;
  }
  if(issue.target_type==='movement'){
    const movement=state.movements.find(row=>String(row.movement_id)===String(issue.movement_id));
    if(movement){loadMovementFocus(movement.movement_id);return}
    navigate('movements');return;
  }
  if(issue.target_type==='dictionary'){navigate('dictionary');return}
  if(issue.target_type==='raw'){recordDetail(issue.date);return}
  navigate(issue.area==='Diet'?'diet':issue.area==='Training'?'training':'body');
}

async function acknowledgeRealIssue(index){
  const issue=state.dataCheck?.issues?.[index];if(!issue)return;
  try{await postApi('/api/data-check/acknowledge',{issue_key:issue.issue_key});state.dataCheck=await api('/api/data-check');await loadArchiveHealth();if(state.dataCheckOverlayOpen){if((state.dataCheck.issues||[]).length===0||state.archiveHealth?.status==='OK'||Number(state.archiveHealth?.issue_count||0)<=0)closeDataCheckOverlay();else renderDataCheckOverlay(state.dataCheck)}else if(state.view==='checks')await checksPage();showToast('该提示已确认并隐藏。')}catch(error){showToast(error.message||'确认失败。')}
}

async function undoLastWebWrite(){
  if(!window.confirm('确定撤销最近一次保存或编辑吗？\n当前数据库和动作词典会一起恢复。'))return;
  try{await postApi('/api/undo',{});invalidateMovementUsage();await refreshWebState();navigate('quick');showToast('最近一次写入已撤销。')}catch(error){showToast(error.message||'撤销失败。')}
}

