async function buildAnalysisExport(){
  const form=$('#export-form');if(!form)return;const values=Object.fromEntries(new FormData(form).entries());values.days=Number(values.days||14);values.include_raw_preview=Boolean(values.include_raw_preview);const button=$('[data-build-export]'),result=$('#export-result');button.disabled=true;button.innerHTML='Preparing export…';result.dataset.status='loading';result.innerHTML='<span class="eyebrow">PREPARING / LOCAL DATA</span><h2>Building<br>your archive.</h2><p>正在整理结构化训练上下文…</p><div class="export-shimmer" aria-hidden="true"></div>';
  try{state.analysisExport=await postApi('/api/analysis-export',values);result.dataset.status='success';result.innerHTML=`<span class="eyebrow">READY / ${esc(state.analysisExport.payload.range.start)} → ${esc(state.analysisExport.payload.range.end)}</span><h2>${state.analysisExport.payload.summary.training_sessions} sessions</h2><p>${state.analysisExport.payload.summary.movement_records} 条动作记录已整理，可以复制或保存到本地。</p><div class="export-manifest"><span>BODY</span><span>DIET</span><span>TRAINING</span><span>MOVEMENT</span><span>QUALITY</span></div><div class="export-actions"><button class="export-object is-copy" data-copy-export="markdown"><span>Copy Markdown</span><small>clipboard</small></button><button class="export-object" data-download-export="markdown"><span>Download .md</span><small>Markdown file</small></button><button class="export-object" data-download-export="json"><span>Download .json</span><small>structured data</small></button></div>`;showToast('分析档案已准备完成。')}catch(error){result.dataset.status='error';result.innerHTML=`<span class="eyebrow">EXPORT FAILED</span><h2>Could not prepare.</h2><p>${esc(error.message||'导出失败，请重试。')}</p>`;showToast(error.message||'导出失败。')}finally{button.disabled=false;button.innerHTML='Generate export <span>→</span>'}
}

function downloadExport(kind){const content=state.analysisExport?.[kind];if(!content)return;const blob=new Blob([content],{type:kind==='json'?'application/json':'text/markdown'}),link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=`fitness-ledger-export.${kind==='json'?'json':'md'}`;link.click();URL.revokeObjectURL(link.href)}

document.addEventListener('click',event=>{
  const target=event.target.closest('[data-undo],[data-real-issue],[data-issue-repair],[data-issue-ack],[data-data-check-close],[data-data-check-detail-close]');if(!target)return;
  event.preventDefault();event.stopImmediatePropagation();
  if(target.dataset.dataCheckClose!==undefined)closeDataCheckOverlay();
  else if(target.dataset.dataCheckDetailClose!==undefined){const detail=$('[data-data-check-detail]');if(detail){detail.hidden=true;detail.innerHTML=''}}
  else if(target.dataset.undo!==undefined)undoLastWebWrite();
  else if(target.dataset.realIssue!==undefined)openRealIssue(Number(target.dataset.realIssue));
  else if(target.dataset.issueRepair!==undefined)repairIssue(Number(target.dataset.issueRepair),target.dataset.repairAction||'editor');
  else if(target.dataset.issueAck!==undefined)acknowledgeRealIssue(Number(target.dataset.issueAck));
},true);

document.addEventListener('click',event=>{const target=event.target.closest('[data-data-check-open],[data-tools-panel]');if(!target)return;event.preventDefault();event.stopImmediatePropagation();if(target.dataset.dataCheckOpen!==undefined){openDataCheckOverlay();return}const panel=target.dataset.toolsPanel;if(panel==='health')navigate('tools',{panel:'health'});else navigate('tools',panel==='overview'?{}:{panel})},true);

document.addEventListener('click',event=>{
  const target=event.target.closest('[data-build-export],[data-copy-export],[data-download-export]');if(!target)return;
  event.preventDefault();event.stopImmediatePropagation();
  if(target.dataset.buildExport!==undefined)buildAnalysisExport();
  else if(target.dataset.copyExport)navigator.clipboard.writeText(state.analysisExport?.[target.dataset.copyExport]||'').then(()=>showToast('已复制到剪贴板。'));
  else if(target.dataset.downloadExport)downloadExport(target.dataset.downloadExport);
},true);
document.addEventListener('click',event=>{const target=event.target.closest('[data-cloud-sync-open],[data-cloud-sync-build],[data-cloud-sync-verify],[data-cloud-sync-preview],[data-cloud-sync-copy],[data-cloud-sync-guide],[data-cloud-sync-directory],[data-cloud-sync-refresh],[data-cloud-sync-check],[data-cloud-sync-steps],[data-cloud-sync-env]');if(!target)return;event.preventDefault();event.stopImmediatePropagation();if(target.dataset.cloudSyncOpen!==undefined)navigate('cloud-sync');else if(target.dataset.cloudSyncBuild!==undefined)buildCloudSync();else if(target.dataset.cloudSyncVerify!==undefined)verifyCloudSync();else if(target.dataset.cloudSyncPreview!==undefined)previewCloudSync();else if(target.dataset.cloudSyncCopy!==undefined)copyCloudSyncReport();else if(target.dataset.cloudSyncDirectory!==undefined)openCloudSyncTarget('directory');else if(target.dataset.cloudSyncGuide!==undefined)openCloudSyncTarget('guide');else if(target.dataset.cloudSyncRefresh!==undefined)cloudSyncPage();else if(target.dataset.cloudSyncCheck!==undefined)cloudSyncCheck(target.dataset.cloudSyncCheck);else if(target.dataset.cloudSyncEnv!==undefined)copyCloudEnvironment();else modal('CloudBase 手动导入步骤','<ol class="cloud-steps"><li>点击“生成 Payload”。</li><li>点击“打开导入目录”。</li><li>在 CloudBase 对应集合中分别导入 JSON 文件。</li><li>导出或复制 fl_meta 单条记录。</li><li>回到“同步后校验”核对云端副本。</li></ol><p class="quiet-note">生成文件不等于云端已更新。</p>')},true);
document.addEventListener('click',event=>{const target=event.target.closest('[data-cloud-sync-run]');if(!target)return;event.preventDefault();event.stopImmediatePropagation();runCloudSync()},true);
document.addEventListener('click',event=>{const target=event.target.closest('button[data-training-theme]');if(!target)return;event.preventDefault();event.stopImmediatePropagation();const next=target.dataset.trainingTheme;state.selectedBodyPart=next==='overview'?null:next;trainingPage()},true);
document.addEventListener('click',event=>{const target=event.target.closest('[data-training-date][data-training-movement-id]');if(!target)return;event.preventDefault();event.stopImmediatePropagation();openTrainingFromMovement(target.dataset.trainingDate,target.dataset.trainingMovementId)},true);
document.addEventListener('mouseover',event=>{const link=event.target.closest('.training-movement-row.is-linkable');if(!link||link.contains(event.relatedTarget))return;schedulePreviousPreview(link)},true);
document.addEventListener('mouseout',event=>{const link=event.target.closest('.training-movement-row.is-linkable');if(!link||link.contains(event.relatedTarget))return;clearPreviousHover()},true);
document.addEventListener('mouseover',event=>{const tile=event.target.closest('.movement-tile.has-index-previous-record');if(!tile||tile.contains(event.relatedTarget))return;scheduleMovementIndexPreviousPreview(tile)},true);
document.addEventListener('mouseout',event=>{const tile=event.target.closest('.movement-tile.has-index-previous-record');if(!tile||tile.contains(event.relatedTarget))return;clearMovementIndexPreviousPreview()},true);
document.addEventListener('focusin',event=>{const tile=event.target.closest('.movement-tile.has-index-previous-record');if(tile)scheduleMovementIndexPreviousPreview(tile)},true);
document.addEventListener('focusout',event=>{if(event.target.closest('.movement-tile.has-index-previous-record'))clearMovementIndexPreviousPreview()},true);
window.addEventListener('scroll',clearMovementIndexPreviousPreview,{passive:true});
window.addEventListener('resize',clearMovementIndexPreviousPreview);

document.addEventListener('compositionstart',()=>{state.composing=true},true);
document.addEventListener('compositionend',()=>{state.composing=false},true);
document.addEventListener('keydown',event=>{if(!(event.ctrlKey||event.metaKey)||event.key.toLowerCase()!=='s'||state.composing||state.saving)return;if(state.view!=='quick'&&state.view!=='review')return;event.preventDefault();if(state.view==='review')saveWebReview();else parseWebEntry()},true);

// Returning through the primary Training route always opens the archive overview.
document.addEventListener('click',event=>{const target=event.target.closest('.nav-item[data-view="training"]');if(target&&state.view!=='training')state.selectedBodyPart=null},true);

// The overview flows directly from the body archive into the record grid. The themed view keeps its distinct Focus Panel.
const trainingPageWithOptionalFocusPanel=trainingPage;
trainingPage=function(...args){trainingPageWithOptionalFocusPanel(...args);if(!state.selectedBodyPart)$('.training-index')?.remove()};

document.addEventListener('click',event=>{const target=event.target.closest('[data-build-identity],[data-build-copy-sha]');if(!target)return;event.preventDefault();event.stopImmediatePropagation();if(target.dataset.buildIdentity!==undefined){openBuildIdentity();return}if(target.dataset.buildCopySha!==undefined){const sha=state.buildInfo?.commit_sha||'';if(!sha)return;const copy=navigator.clipboard?.writeText?navigator.clipboard.writeText(sha):Promise.reject(new Error('clipboard unavailable'));copy.then(()=>showToast('完整 Commit SHA 已复制。')).catch(()=>showToast('当前环境无法访问剪贴板。'))}},true);
window.addEventListener('popstate',()=>renderRoute(parseRoute(),history.state||{}));window.addEventListener('hashchange',()=>{const route=parseRoute();if(route.view!==state.view||route.params.toString()!==new URLSearchParams(state.routeParams||{}).toString())renderRoute(route,history.state||{})});load();
loadBuildInfo();
window.addEventListener('resize',()=>{if(state.view==='training')requestAnimationFrame(layoutTrainingGrid)});
